INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL valid steps when upgrading a kubeadm WORKER node.$k8s$, $k8s$[{"id":"a","text":"`kubectl drain <node> --ignore-daemonsets` from a control plane."},{"id":"b","text":"`kubeadm upgrade node` on the worker."},{"id":"c","text":"Upgrade the kubelet/kubectl packages and restart the kubelet."},{"id":"d","text":"`kubectl uncordon <node>` afterwards."}]$k8s$::jsonb, $k8s$["a","b","c","d"]$k8s$::jsonb, $k8s$All four are part of the documented worker upgrade: drain, `kubeadm upgrade node`, upgrade kubelet/kubectl + restart, then uncordon to resume scheduling.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/kubeadm/kubeadm-upgrade/","label":"Kubernetes Docs — Upgrading kubeadm clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL valid steps when upgrading a kubeadm WORKER node.$k8s$);
