INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod must tolerate a node tainted `gpu=true:NoSchedule` AND only land on GPU nodes labelled `gpu=true`. You need:$k8s$, $k8s$[{"id":"a","text":"a matching toleration plus a nodeSelector/affinity for the label"},{"id":"b","text":"only a toleration"},{"id":"c","text":"only a nodeSelector"},{"id":"d","text":"a PriorityClass"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A toleration only permits scheduling onto the tainted node; it does not attract the Pod there. Add a nodeSelector or nodeAffinity on `gpu=true` to also require placement on GPU nodes.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/","label":"Kubernetes Docs — Taints and Tolerations"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod must tolerate a node tainted `gpu=true:NoSchedule` AND only land on GPU nodes labelled `gpu=true`. You need:$k8s$);
