INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about node affinity.$k8s$, $k8s$[{"id":"a","text":"requiredDuringSchedulingIgnoredDuringExecution is a hard rule."},{"id":"b","text":"preferredDuringScheduling... is a soft (weighted) preference."},{"id":"c","text":"Affinity rules are re-evaluated and Pods evicted if labels change later."},{"id":"d","text":"It can express richer set-based label matching than nodeSelector."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$`IgnoredDuringExecution` means running Pods are NOT evicted when node labels change. Required is hard, preferred is soft/weighted, and affinity supports operators like In/NotIn/Exists.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about node affinity.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$Topology spread constraints with `maxSkew: 1` and `topologyKey: zone` aim to:$k8s$, $k8s$[{"id":"a","text":"distribute Pods so the count difference between zones is at most 1"},{"id":"b","text":"allow at most 1 Pod per zone"},{"id":"c","text":"place all Pods in one zone"},{"id":"d","text":"evict Pods when zones become unbalanced"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`maxSkew` bounds the permitted imbalance of matching Pods across topology domains (zones), spreading them evenly. It is a scheduling constraint, not a runtime eviction mechanism.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Topology spread constraints with `maxSkew: 1` and `topologyKey: zone` aim to:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$Setting `spec.nodeName` directly on a Pod bypasses the scheduler and binds the Pod to that node.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$True. A Pod with `nodeName` set is assigned to that node without scheduler involvement; it will fail if that node lacks capacity or does not exist.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Setting `spec.nodeName` directly on a Pod bypasses the scheduler and binds the Pod to that node.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command imperatively creates a ClusterIP Service for Deployment `api` on port 80?$k8s$, $k8s$[{"id":"a","text":"kubectl expose deploy api --port=80"},{"id":"b","text":"kubectl create svc api --port 80"},{"id":"c","text":"kubectl run svc api --port=80"},{"id":"d","text":"kubectl service create api 80"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl expose deploy api --port=80` creates a Service (ClusterIP by default) selecting the Deployment's Pods. `--target-port` sets the container port if it differs.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command imperatively creates a ClusterIP Service for Deployment `api` on port 80?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A NodePort Service is created. Which port range will Kubernetes allocate by default?$k8s$, $k8s$[{"id":"a","text":"30000–32767"},{"id":"b","text":"1–1024"},{"id":"c","text":"8080–8443"},{"id":"d","text":"40000–49999"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$The default `--service-node-port-range` is 30000–32767. A specific `nodePort` can be requested within that range; conflicts are rejected.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A NodePort Service is created. Which port range will Kubernetes allocate by default?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Two Pods in different namespaces cannot communicate after you add a default-deny NetworkPolicy. To allow cross-namespace traffic you must:$k8s$, $k8s$[{"id":"a","text":"add an ingress rule with a namespaceSelector matching the source namespace labels"},{"id":"b","text":"delete kube-proxy"},{"id":"c","text":"switch the Service to NodePort"},{"id":"d","text":"set hostNetwork: true"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$With a default-deny policy in place you must explicitly allow the source via a `from` peer using a `namespaceSelector` (and optionally `podSelector`) matching the other namespace.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Two Pods in different namespaces cannot communicate after you add a default-deny NetworkPolicy. To allow cross-namespace traffic you must:$k8s$);
