INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about NetworkPolicy default behavior.$k8s$, $k8s$[{"id":"a","text":"With no policies, all Pod traffic is allowed."},{"id":"b","text":"A policy selecting a Pod for Ingress makes that Pod default-deny for non-matching ingress."},{"id":"c","text":"NetworkPolicy requires a CNI that implements it."},{"id":"d","text":"Egress is restricted only if policyTypes includes Egress."}]$k8s$::jsonb, $k8s$["a","b","c","d"]$k8s$::jsonb, $k8s$All four are correct. Pods are non-isolated until a policy selects them; once selected for a direction, only explicitly allowed traffic in that direction is permitted, and enforcement depends on the CNI.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about NetworkPolicy default behavior.$k8s$);
