INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command lists all PersistentVolumes and their bound claims/status?$k8s$, $k8s$[{"id":"a","text":"kubectl get pv"},{"id":"b","text":"kubectl get volumes"},{"id":"c","text":"kubectl describe storage"},{"id":"d","text":"kubectl get pvc -A --show-pv"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl get pv` shows each PV with capacity, access modes, reclaim policy, status, and the bound claim. `kubectl get pvc` shows the claim side.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command lists all PersistentVolumes and their bound claims/status?$k8s$);
