INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You expand a PVC by editing `spec.resources.requests.storage` but the new size is not reflected. The MOST likely reason is:$k8s$, $k8s$[{"id":"a","text":"allowVolumeExpansion is not true on the StorageClass."},{"id":"b","text":"The PVC is ReadWriteOnce."},{"id":"c","text":"The Pod is not labelled."},{"id":"d","text":"reclaimPolicy is Retain."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Online expansion requires `allowVolumeExpansion: true` on the StorageClass; without it the larger request is rejected/ignored by the provisioner.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You expand a PVC by editing `spec.resources.requests.storage` but the new size is not reflected. The MOST likely reason is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod must read a Secret as files at `/etc/creds`. The correct volume type is:$k8s$, $k8s$[{"id":"a","text":"a secret volume mounted at /etc/creds"},{"id":"b","text":"an emptyDir volume"},{"id":"c","text":"a hostPath volume"},{"id":"d","text":"a downwardAPI volume"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A `secret` volume projects each Secret key as a file under the mount path. `downwardAPI` exposes Pod metadata, not Secret data; emptyDir/hostPath do not source Secret contents.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/volumes/","label":"Kubernetes Docs — Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod must read a Secret as files at `/etc/creds`. The correct volume type is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A PVC can bind to a PV only if the PV capacity is greater than or equal to the requested size and the access modes are compatible.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$True. Binding requires the PV capacity ≥ the PVC request and the requested access mode to be among the PV access modes (StorageClass must also match if specified).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A PVC can bind to a PV only if the PV capacity is greater than or equal to the requested size and the access modes are compatible.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command shows the node a Pod is scheduled on plus its Pod IP?$k8s$, $k8s$[{"id":"a","text":"kubectl get pod <pod> -o wide"},{"id":"b","text":"kubectl logs <pod>"},{"id":"c","text":"kubectl top pod <pod>"},{"id":"d","text":"kubectl get pod <pod> --short"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl get pod -o wide` adds NODE, IP, and NOMINATED NODE columns — the quickest way to see placement during triage.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command shows the node a Pod is scheduled on plus its Pod IP?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod is `Pending` and describe shows "node(s) didn't match Pod's node affinity/selector". The fix is:$k8s$, $k8s$[{"id":"a","text":"Correct the nodeSelector/affinity or label a node to match."},{"id":"b","text":"Increase Pod CPU limits."},{"id":"c","text":"Restart the scheduler."},{"id":"d","text":"Add an imagePullSecret."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$No node satisfies the Pod's node affinity/selector. Either relax/fix the constraint or add the required label to a suitable node so the scheduler can place the Pod.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod is `Pending` and describe shows "node(s) didn't match Pod's node affinity/selector". The fix is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A container is `CreateContainerConfigError`. `kubectl describe pod` shows "secret \"db-cred\" not found". The remediation is:$k8s$, $k8s$[{"id":"a","text":"Create the missing Secret `db-cred` in the Pod namespace."},{"id":"b","text":"Restart the kubelet."},{"id":"c","text":"Recreate the node."},{"id":"d","text":"Add a liveness probe."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$CreateContainerConfigError commonly means a referenced ConfigMap/Secret is missing. Create `db-cred` in the same namespace; the kubelet then starts the container.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A container is `CreateContainerConfigError`. `kubectl describe pod` shows "secret \"db-cred\" not found". The remediation is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need to test connectivity from inside the cluster to a Service. The quickest approach is:$k8s$, $k8s$[{"id":"a","text":"kubectl run tmp --rm -it --image=busybox -- wget -qO- http://<svc>:<port>"},{"id":"b","text":"curl from your laptop directly to the ClusterIP"},{"id":"c","text":"kubectl get svc -o yaml"},{"id":"d","text":"ping the Service DNS from the control-plane host"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A throwaway Pod (`kubectl run --rm -it`) tests Service reachability from within the cluster network — ClusterIPs are not routable from outside or from the host.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need to test connectivity from inside the cluster to a Service. The quickest approach is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$The scheduler Pod is healthy but no Pods are being scheduled cluster-wide. A likely cause to check is:$k8s$, $k8s$[{"id":"a","text":"All nodes are cordoned/NotReady or tainted so no node is feasible."},{"id":"b","text":"CoreDNS is down."},{"id":"c","text":"kubectl is outdated."},{"id":"d","text":"The dashboard is disabled."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$If every node is cordoned, NotReady, or carries a NoSchedule taint, the scheduler has no feasible node. Check `kubectl get nodes` and node taints/conditions.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$The scheduler Pod is healthy but no Pods are being scheduled cluster-wide. A likely cause to check is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A node's kubelet logs show "failed to run Kubelet: misconfiguration: kubelet cgroup driver: cgroupfs is different from runtime cgroup driver: systemd". The fix is:$k8s$, $k8s$[{"id":"a","text":"Align kubelet and runtime cgroup drivers (set both to systemd)."},{"id":"b","text":"Disable the firewall."},{"id":"c","text":"Reinstall kubectl."},{"id":"d","text":"Delete /var/lib/etcd."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$The kubelet and container runtime must use the same cgroup driver. Set `cgroupDriver: systemd` in the kubelet config and ensure containerd uses `SystemdCgroup = true`, then restart both.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/container-runtimes/","label":"Kubernetes Docs — Container Runtimes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A node's kubelet logs show "failed to run Kubelet: misconfiguration: kubelet cgroup driver: cgroupfs is different from runtime cgroup driver: systemd". The fix is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment shows the desired replicas but 0 available, and Pods are `0/1 Running`. The MOST likely cause is:$k8s$, $k8s$[{"id":"a","text":"The readiness probe is failing so Pods are Running but not Ready."},{"id":"b","text":"The image cannot be pulled."},{"id":"c","text":"etcd is down."},{"id":"d","text":"The Service has no selector."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`0/1 Running` means the container runs but the readiness probe fails, so the Pod is not Ready and not counted as available. Inspect/fix the readiness probe or the app.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment shows the desired replicas but 0 available, and Pods are `0/1 Running`. The MOST likely cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$After a node reboot, its Pods are not rescheduled and the node stays `NotReady`. The first thing to check is:$k8s$, $k8s$[{"id":"a","text":"Whether the kubelet and container runtime services started on boot (systemctl is-enabled)."},{"id":"b","text":"Whether CoreDNS scaled down."},{"id":"c","text":"Whether the Service is ClusterIP."},{"id":"d","text":"Whether kubectl is configured."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$After reboot a NotReady node usually means kubelet/containerd did not start. Verify they are enabled and running (`systemctl status/enable kubelet containerd`).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$After a node reboot, its Pods are not rescheduled and the node stays `NotReady`. The first thing to check is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$kube-controller-manager is CrashLoopBackOff after editing its static Pod manifest. The fastest way to see the parse/flag error is:$k8s$, $k8s$[{"id":"a","text":"crictl logs of the controller-manager container on the control-plane node"},{"id":"b","text":"kubectl logs -n kube-system deploy/kube-controller-manager"},{"id":"c","text":"systemctl status kube-controller-manager"},{"id":"d","text":"kubectl rollout status"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$It is a static Pod, so use `crictl ps -a` + `crictl logs` (or `/var/log/pods`) on the node. A bad flag/YAML in the manifest is the usual culprit; fix the manifest and the kubelet restarts it.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$kube-controller-manager is CrashLoopBackOff after editing its static Pod manifest. The fastest way to see the parse/flag error is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod cannot resolve external domains but resolves cluster Services fine. The likely cause is:$k8s$, $k8s$[{"id":"a","text":"CoreDNS upstream forwarders (or node /etc/resolv.conf) are misconfigured."},{"id":"b","text":"The Pod has no Service."},{"id":"c","text":"kube-proxy is in IPVS mode."},{"id":"d","text":"The image lacks curl."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Cluster names resolving but external names failing points to CoreDNS upstream forwarding (the `forward` plugin / node resolv.conf) being broken. Fix the upstream resolver configuration.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod cannot resolve external domains but resolves cluster Services fine. The likely cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You must capture a failing Pod's describe output and recent events for a ticket. The single best command is:$k8s$, $k8s$[{"id":"a","text":"kubectl describe pod <pod> -n <ns>"},{"id":"b","text":"kubectl get pod <pod> -o name"},{"id":"c","text":"kubectl logs <pod> --tail=1"},{"id":"d","text":"kubectl top pod <pod>"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl describe pod` consolidates spec status, container states, conditions, and the associated events — the primary first-look troubleshooting command.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You must capture a failing Pod's describe output and recent events for a ticket. The single best command is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$A Pod is stuck in `ImagePullBackOff`. Select ALL valid causes.$k8s$, $k8s$[{"id":"a","text":"The image name or tag is wrong / does not exist."},{"id":"b","text":"The registry requires auth and no imagePullSecret is set."},{"id":"c","text":"The node cannot reach the registry network."},{"id":"d","text":"The Service selector does not match the Pod."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$ImagePullBackOff is purely about pulling the image: wrong name/tag, missing registry credentials, or no network path to the registry. A Service selector mismatch is unrelated to image pulls.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod is stuck in `ImagePullBackOff`. Select ALL valid causes.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$`kubectl get events -n <ns>` is useful for diagnosing why a Pod failed to schedule or pull its image.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$True. Scheduling failures, image pull errors, and probe failures are recorded as Events; listing them (sorted by time) is a core triage step alongside `kubectl describe`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$`kubectl get events -n <ns>` is useful for diagnosing why a Pod failed to schedule or pull its image.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A user `dev1` must be able to list and get Pods cluster-wide but mutate nothing. The MINIMUM RBAC binding required is:$k8s$, $k8s$[{"id":"a","text":"A Role + RoleBinding in every namespace."},{"id":"b","text":"A ClusterRole with `verbs: [get,list,watch]` on `pods` + a ClusterRoleBinding to user `dev1`."},{"id":"c","text":"A ClusterRole with `verbs: [\"*\"]` + ClusterRoleBinding."},{"id":"d","text":"A Role with `verbs: [\"*\"]` + RoleBinding to the default namespace."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Cluster-wide read of a core resource is a ClusterRole bound via ClusterRoleBinding. A Role is namespace-scoped; wildcard verbs over-privilege.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A user `dev1` must be able to list and get Pods cluster-wide but mutate nothing. The MINIMUM RBAC binding required is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command renders the spec of an installed CRD field so you can author a CR against it?$k8s$, $k8s$[{"id":"a","text":"kubectl describe crd <name>"},{"id":"b","text":"kubectl explain <kind>.<path> (e.g. certificates.spec.subject)"},{"id":"c","text":"kubectl api-versions"},{"id":"d","text":"kubectl proxy --crd"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`kubectl explain` reads the openAPI schema from the apiserver, including CRD schemas. It supports dotted paths for nested fields.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/api-extension/custom-resources/","label":"Kubernetes Docs — Custom Resources"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command renders the spec of an installed CRD field so you can author a CR against it?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$After `kubeadm init`, the message instructs you to run `kubectl ... --kubeconfig=/etc/kubernetes/admin.conf` or copy that file to `$HOME/.kube/config`. Which is INCORRECT about that file?$k8s$, $k8s$[{"id":"a","text":"It contains an admin client cert/key."},{"id":"b","text":"It is safe to share with developers as-is."},{"id":"c","text":"Its CA cert matches the apiserver's cert."},{"id":"d","text":"Its server URL is the apiserver advertise address."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`admin.conf` is cluster-admin; never hand it to developers. Generate per-user kubeconfigs (e.g. via `kubeadm kubeconfig user`) with scoped RBAC.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"},{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$After `kubeadm init`, the message instructs you to run `kubectl ... --kubeconfig=/etc/kubernetes/admin.conf` or copy that file to `$HOME/.kube/config`. Which is INCORRECT about that file?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$On a fresh single-node cluster, after `kubeadm init` the apiserver is healthy but `kubectl get nodes` shows the node `NotReady`. The MOST likely remaining step is:$k8s$, $k8s$[{"id":"a","text":"Apply a CNI manifest (e.g. Calico / Flannel) so the node Ready condition can transition."},{"id":"b","text":"Restart the kubelet."},{"id":"c","text":"Set `--allow-privileged=true` on the apiserver."},{"id":"d","text":"Disable swap (kubeadm already does this)."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Node Ready requires a working network plugin. Without a CNI the kubelet reports `NetworkUnavailable` and the node stays NotReady.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$On a fresh single-node cluster, after `kubeadm init` the apiserver is healthy but `kubectl get nodes` shows the node `NotReady`. The MOST likely remaining step is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL valid placements for cri-dockerd in a CKA exam context.$k8s$, $k8s$[{"id":"a","text":"cri-dockerd is required if you keep Docker as the runtime past k8s 1.24."},{"id":"b","text":"cri-dockerd is a CRI shim that lets the kubelet talk to dockerd."},{"id":"c","text":"cri-dockerd is a CNI plugin."},{"id":"d","text":"Default kubeadm clusters typically use containerd, not cri-dockerd."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$cri-dockerd is a runtime shim, not a CNI plugin. It exists because the in-tree dockershim was removed in 1.24. Modern kubeadm clusters default to containerd.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/container-runtimes/","label":"Kubernetes Docs — Container Runtimes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL valid placements for cri-dockerd in a CKA exam context.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Two Pods MUST run on different nodes. Which scheduling primitive expresses this?$k8s$, $k8s$[{"id":"a","text":"podAffinity with `topologyKey: kubernetes.io/hostname`"},{"id":"b","text":"podAntiAffinity with `topologyKey: kubernetes.io/hostname`"},{"id":"c","text":"nodeSelector: { distinct: \"true\" }"},{"id":"d","text":"PriorityClass preemption"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$PodAntiAffinity with hostname topology rejects nodes that already run a matching Pod, achieving spread-by-host.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/assign-pod-node/","label":"Kubernetes Docs — Assigning Pods to Nodes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Two Pods MUST run on different nodes. Which scheduling primitive expresses this?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need a sidecar that runs FOR THE LIFETIME of the main container and shares a log volume. In recent Kubernetes versions, the recommended way is:$k8s$, $k8s$[{"id":"a","text":"Add it as a second container under `spec.containers[]` sharing an emptyDir volume."},{"id":"b","text":"Add it as an initContainer."},{"id":"c","text":"Run it as a separate Deployment."},{"id":"d","text":"Use a Job."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Classic sidecars are simply additional containers in the Pod sharing volumes. The native "sidecar initContainer" (`restartPolicy: Always` on an initContainer) is a newer beta pattern for sidecars whose startup must precede the main container.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need a sidecar that runs FOR THE LIFETIME of the main container and shares a log volume. In recent Kubernetes versions, the recommended way is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment has 3 replicas and `maxSurge: 1, maxUnavailable: 0`. During rollout, how many Pods total can exist simultaneously?$k8s$, $k8s$[{"id":"a","text":"3"},{"id":"b","text":"4"},{"id":"c","text":"5"},{"id":"d","text":"6"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`maxSurge: 1` allows one extra Pod above desired (3 → up to 4). `maxUnavailable: 0` blocks dropping below desired Ready count.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment has 3 replicas and `maxSurge: 1, maxUnavailable: 0`. During rollout, how many Pods total can exist simultaneously?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You want headless DNS so clients can resolve INDIVIDUAL Pod IPs of a StatefulSet. The Service config is:$k8s$, $k8s$[{"id":"a","text":"type: ClusterIP, clusterIP: None, selector: { app: db }"},{"id":"b","text":"type: NodePort, headless: true"},{"id":"c","text":"type: ExternalName, externalName: db"},{"id":"d","text":"type: ClusterIP with externalTrafficPolicy: Local"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Setting `clusterIP: None` (with a selector) makes the Service headless. CoreDNS returns A records for each backing Pod's IP — required for StatefulSet stable per-Pod DNS.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"},{"url":"https://kubernetes.io/docs/concepts/services-networking/dns-pod-service/","label":"Kubernetes Docs — DNS for Services and Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You want headless DNS so clients can resolve INDIVIDUAL Pod IPs of a StatefulSet. The Service config is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A NetworkPolicy applied to `podSelector: {}` with `policyTypes: [Ingress, Egress]` and no `ingress`/`egress` rules has what effect on Pods in that namespace?$k8s$, $k8s$[{"id":"a","text":"Allow all ingress and egress."},{"id":"b","text":"Default-deny all ingress AND all egress."},{"id":"c","text":"No effect."},{"id":"d","text":"Default-deny only intra-namespace traffic."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$An empty selector matches every Pod; declaring both policyTypes with empty rule lists denies all traffic of those types. This is the classic "default deny" pattern.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A NetworkPolicy applied to `podSelector: {}` with `policyTypes: [Ingress, Egress]` and no `ingress`/`egress` rules has what effect on Pods in that namespace?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$In the `gateway.networking.k8s.io/v1` API, which resource declares the controller implementation (e.g. nginx) that processes Gateways?$k8s$, $k8s$[{"id":"a","text":"GatewayClass"},{"id":"b","text":"Gateway"},{"id":"c","text":"HTTPRoute"},{"id":"d","text":"ReferenceGrant"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`GatewayClass` is the cluster-scoped resource that names the controller (e.g. `nginx`). A Gateway selects a GatewayClass; HTTPRoute attaches to a Gateway.$k8s$, $k8s$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$In the `gateway.networking.k8s.io/v1` API, which resource declares the controller implementation (e.g. nginx) that processes Gateways?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$An Ingress route 80→8080 stops working after migrating from ingress-nginx Ingress to a Gateway+HTTPRoute. Both resources exist temporarily. The CORRECT cleanup is:$k8s$, $k8s$[{"id":"a","text":"Delete the old Ingress with `kubectl delete ingress <name> -n <ns>`."},{"id":"b","text":"Leave both — they coexist."},{"id":"c","text":"Delete the GatewayClass."},{"id":"d","text":"Set the Ingress annotation `disabled: true`."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Once HTTPRoute is verified working, delete the Ingress to avoid double-routing and resource churn. There is no `disabled: true` annotation in the Ingress API.$k8s$, $k8s$[{"url":"https://gateway-api.sigs.k8s.io/","label":"Kubernetes Docs — Gateway API"},{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$An Ingress route 80→8080 stops working after migrating from ingress-nginx Ingress to a Gateway+HTTPRoute. Both resources exist temporarily. The CORRECT cleanup is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need a StatefulSet whose Pods each get their own PVC sized 1Gi. The mechanism is:$k8s$, $k8s$[{"id":"a","text":"spec.volumeClaimTemplates on the StatefulSet"},{"id":"b","text":"spec.template.spec.volumes (one PVC reused)"},{"id":"c","text":"A Deployment with `replicas: N` and a shared PVC"},{"id":"d","text":"PriorityClass with `volumeQuota`"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`volumeClaimTemplates` materializes a fresh PVC per ordinal Pod, satisfying per-Pod persistence in StatefulSets. A single PVC referenced via `volumes` would be shared — not what you want.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need a StatefulSet whose Pods each get their own PVC sized 1Gi. The mechanism is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A PVC of size 1Gi must be expanded to 5Gi online. The PRE-REQUISITE on the StorageClass is:$k8s$, $k8s$[{"id":"a","text":"reclaimPolicy: Retain"},{"id":"b","text":"allowVolumeExpansion: true"},{"id":"c","text":"volumeBindingMode: Immediate"},{"id":"d","text":"parameters.fsType: ext4"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`allowVolumeExpansion: true` on the StorageClass is required; then editing the PVC `resources.requests.storage` triggers an online resize (provisioner-dependent).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A PVC of size 1Gi must be expanded to 5Gi online. The PRE-REQUISITE on the StorageClass is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod's containerPort `80` is declared but the Service's `targetPort` is `8080`. Symptom?$k8s$, $k8s$[{"id":"a","text":"503 / connection refused — Service forwards to a port the Pod is not listening on."},{"id":"b","text":"Pods crash on startup."},{"id":"c","text":"NetworkPolicy blocks the traffic."},{"id":"d","text":"Ingress returns 404."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Service `targetPort` is the Pod port the kube-proxy DNATs to. A mismatch with the actually-listening port produces refused/timeout — not a Pod crash.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod's containerPort `80` is declared but the Service's `targetPort` is `8080`. Symptom?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You suspect the scheduler is wedged. Which command surfaces "FailedScheduling" reasons for a specific Pod?$k8s$, $k8s$[{"id":"a","text":"kubectl get events --field-selector involvedObject.name=<pod>"},{"id":"b","text":"kubectl logs deploy/kube-scheduler -n kube-system"},{"id":"c","text":"kubectl describe deploy <pod>"},{"id":"d","text":"kubectl proxy --debug"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl describe pod <pod>` also surfaces the same events. Filtering via field-selector is a more programmatic equivalent. Scheduler logs help too but require deeper access.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You suspect the scheduler is wedged. Which command surfaces "FailedScheduling" reasons for a specific Pod?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$kube-proxy is logging "can't open iptables lock". The fix is:$k8s$, $k8s$[{"id":"a","text":"Run kube-proxy with hostNetwork (it already does)."},{"id":"b","text":"Add the privileged securityContext or required capabilities; ensure xtables-lock is mounted from /run/xtables.lock."},{"id":"c","text":"Disable iptables and use ipvs without configuration."},{"id":"d","text":"Restart the apiserver."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$kube-proxy manipulates iptables on the host and needs the host's xtables lock and capabilities (NET_ADMIN, SYS_MODULE). The canonical DaemonSet manifest mounts `/run/xtables.lock`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$kube-proxy is logging "can't open iptables lock". The fix is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Pods on `node02` are stuck in `ContainerCreating`. `kubectl describe pod` shows "NetworkPlugin cni failed to set up pod ... no IP addresses available in range set". The MOST likely root cause is:$k8s$, $k8s$[{"id":"a","text":"PodCIDR allocated to the node is exhausted — investigate via the CNI and free / expand the range."},{"id":"b","text":"kube-proxy is down."},{"id":"c","text":"CoreDNS is broken."},{"id":"d","text":"NodePort range is full."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Each node gets a slice of the cluster Pod CIDR. When that range is exhausted, the CNI IPAM returns "no IP available". Solutions: increase per-node range or scale out nodes.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Pods on `node02` are stuck in `ContainerCreating`. `kubectl describe pod` shows "NetworkPlugin cni failed to set up pod ... no IP addresses available in range set". The MOST likely root cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$`kubectl drain node01 --ignore-daemonsets --delete-emptydir-data` hangs on a PodDisruptionBudget. The CORRECT next step is:$k8s$, $k8s$[{"id":"a","text":"Wait for capacity to free up so the eviction can complete."},{"id":"b","text":"Use --force --grace-period=0 to delete the Pods (last resort — bypasses graceful termination)."},{"id":"c","text":"Delete the PDB without consideration."},{"id":"d","text":"kubeadm reset node01"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A PDB respecting eviction will block until enough replicas can be moved while satisfying minAvailable. Scaling out (or rescheduling other Pods) typically unblocks the drain. `--force` is the destructive escape hatch.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$`kubectl drain node01 --ignore-daemonsets --delete-emptydir-data` hangs on a PodDisruptionBudget. The CORRECT next step is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$`kubectl exec` returns "error: unable to upgrade connection: container not found ("XYZ")" yet the Pod is Running. The MOST likely cause is:$k8s$, $k8s$[{"id":"a","text":"Pod has multiple containers and you must pass `-c <name>` for the right one."},{"id":"b","text":"apiserver is down."},{"id":"c","text":"kubelet TLS cert has expired."},{"id":"d","text":"NetworkPolicy blocks exec."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$When the pod has multiple containers, omitting `-c` selects the default, which may not exist by the name kubectl is logging in the error. Specify the container explicitly.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$`kubectl exec` returns "error: unable to upgrade connection: container not found ("XYZ")" yet the Pod is Running. The MOST likely cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which kubeadm phase command pre-pulls the container images required for the control plane?$k8s$, $k8s$[{"id":"a","text":"kubeadm config images pull"},{"id":"b","text":"kubeadm init --pull-images"},{"id":"c","text":"crictl pull kubeadm"},{"id":"d","text":"kubectl get images -A"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubeadm config images pull` downloads the apiserver, controller-manager, scheduler, etcd, and pause images ahead of `kubeadm init` to speed up and de-risk the bootstrap.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which kubeadm phase command pre-pulls the container images required for the control plane?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A ClusterRole aggregation should automatically include rules from labelled ClusterRoles. The mechanism is:$k8s$, $k8s$[{"id":"a","text":"spec.aggregationRule.clusterRoleSelectors on the aggregate ClusterRole"},{"id":"b","text":"metadata.ownerReferences"},{"id":"c","text":"a RoleBinding with `aggregate: true`"},{"id":"d","text":"the `rbac.authorization.k8s.io/aggregate` Service annotation"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$An aggregated ClusterRole uses `aggregationRule.clusterRoleSelectors`; the controller merges rules from any ClusterRole whose labels match. The aggregate role's own `rules` are managed by the controller.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/reference/access-authn-authz/rbac/","label":"Kubernetes Docs — RBAC"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A ClusterRole aggregation should automatically include rules from labelled ClusterRoles. The mechanism is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$To rotate a leaked bootstrap token, you should:$k8s$, $k8s$[{"id":"a","text":"kubeadm token delete <token-id> and create a new one when needed"},{"id":"b","text":"restart the apiserver"},{"id":"c","text":"rotate the etcd snapshot"},{"id":"d","text":"kubectl delete secret kube-proxy"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Bootstrap tokens live as Secrets in kube-system; `kubeadm token delete` revokes a leaked token immediately. Generate a fresh one with `kubeadm token create --print-join-command` only when joining nodes.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$To rotate a leaked bootstrap token, you should:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You must change the cluster's API server `--audit-log-path`. On a kubeadm cluster you edit:$k8s$, $k8s$[{"id":"a","text":"/etc/kubernetes/manifests/kube-apiserver.yaml (static Pod manifest)"},{"id":"b","text":"/etc/systemd/system/kube-apiserver.service"},{"id":"c","text":"the kube-apiserver ConfigMap in kube-system"},{"id":"d","text":"kubectl edit deploy kube-apiserver"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$apiserver flags are set as container args in its static Pod manifest. After saving, the kubelet recreates the Pod with the new flag. No systemd unit/Deployment/ConfigMap drives it.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/control-plane-flags/","label":"Kubernetes Docs — kube-apiserver Static Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You must change the cluster's API server `--audit-log-path`. On a kubeadm cluster you edit:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which etcdctl command verifies the integrity/metadata of a saved snapshot file?$k8s$, $k8s$[{"id":"a","text":"ETCDCTL_API=3 etcdctl snapshot status /backup/snap.db"},{"id":"b","text":"etcdctl verify snapshot /backup/snap.db"},{"id":"c","text":"etcdctl snapshot check"},{"id":"d","text":"kubectl get etcd snapshot"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`etcdctl snapshot status <file>` prints the snapshot's hash, revision, and total keys, confirming it is a valid v3 snapshot before relying on it for restore.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which etcdctl command verifies the integrity/metadata of a saved snapshot file?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command removes a node cleanly from the cluster after draining it?$k8s$, $k8s$[{"id":"a","text":"kubectl delete node <node> (then `kubeadm reset` on the node)"},{"id":"b","text":"kubectl cordon <node>"},{"id":"c","text":"kubeadm token delete <node>"},{"id":"d","text":"systemctl stop kubelet only"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$After `kubectl drain`, remove the node object with `kubectl delete node`, then run `kubeadm reset` on the host to clean its cluster state and config files.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command removes a node cleanly from the cluster after draining it?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A kubeadm `kubeadm join` fails with "couldn't validate the identity of the API Server: cluster CA hash ... does not match". The cause is:$k8s$, $k8s$[{"id":"a","text":"A stale/incorrect --discovery-token-ca-cert-hash on the join command."},{"id":"b","text":"The worker has swap enabled."},{"id":"c","text":"CoreDNS is down."},{"id":"d","text":"The worker kubelet is too new."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$The CA cert hash pins the API server identity during discovery. A mismatched/old hash (e.g. CA rotated) fails validation. Regenerate the join command with `kubeadm token create --print-join-command`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A kubeadm `kubeadm join` fails with "couldn't validate the identity of the API Server: cluster CA hash ... does not match". The cause is:$k8s$);
