INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL files/dirs kubeadm uses for control-plane state on a control-plane node.$k8s$, $k8s$[{"id":"a","text":"/etc/kubernetes/manifests (static Pod manifests)"},{"id":"b","text":"/etc/kubernetes/pki (cluster certificates)"},{"id":"c","text":"/var/lib/etcd (etcd data dir)"},{"id":"d","text":"/etc/kubernetes/admin.conf (admin kubeconfig)"}]$k8s$::jsonb, $k8s$["a","b","c","d"]$k8s$::jsonb, $k8s$All four are kubeadm-managed: static Pod manifests, the PKI directory, the etcd data directory, and the admin kubeconfig. Knowing these paths is essential for backup/restore and troubleshooting.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"},{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL files/dirs kubeadm uses for control-plane state on a control-plane node.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Cluster Architecture, Installation and Configuration$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$On a kubeadm cluster, etcd serves client requests on port 2379 and peer (replication) traffic on port 2380.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$True. 2379 is the etcd client port (used by the apiserver); 2380 is the peer port for inter-member replication. The apiserver must point at 2379.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$On a kubeadm cluster, etcd serves client requests on port 2379 and peer (replication) traffic on port 2380.$k8s$);
