INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Workloads and Scheduling$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about resource requests and limits.$k8s$, $k8s$[{"id":"a","text":"Requests influence scheduling (node must have enough allocatable)."},{"id":"b","text":"Exceeding a memory limit causes an OOMKill."},{"id":"c","text":"Exceeding a CPU limit throttles the container (not killed)."},{"id":"d","text":"A Pod with no requests is rejected by the apiserver."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$A Pod without requests/limits is allowed (it becomes BestEffort QoS). Requests drive scheduling, memory-over-limit is OOMKilled, and CPU-over-limit is throttled rather than killed.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about resource requests and limits.$k8s$);
