INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which field selects which Ingress controller implements a given Ingress object?$k8s$, $k8s$[{"id":"a","text":"spec.ingressClassName"},{"id":"b","text":"metadata.namespace"},{"id":"c","text":"spec.rules[].host"},{"id":"d","text":"spec.backend.service.name"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`spec.ingressClassName` (referencing an IngressClass) tells which controller should program the Ingress. A default IngressClass is used if the field is omitted and one is marked default.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which field selects which Ingress controller implements a given Ingress object?$k8s$);
