INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command shows the EndpointSlices (backends) for Service `web`?$k8s$, $k8s$[{"id":"a","text":"kubectl get endpointslices -l kubernetes.io/service-name=web"},{"id":"b","text":"kubectl get pods --svc web"},{"id":"c","text":"kubectl describe networkpolicy web"},{"id":"d","text":"kubectl get ingress web -o endpoints"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$EndpointSlices are labelled with `kubernetes.io/service-name`. Filtering by that label lists the slices (and thus the backend IPs) for a Service — handy when a Service has no working endpoints.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command shows the EndpointSlices (backends) for Service `web`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about ClusterIP vs NodePort vs LoadBalancer Services.$k8s$, $k8s$[{"id":"a","text":"NodePort builds on ClusterIP and additionally opens a port on every node."},{"id":"b","text":"LoadBalancer builds on NodePort and provisions an external LB (cloud) or needs MetalLB on bare metal."},{"id":"c","text":"ClusterIP is the default and is internal-only."},{"id":"d","text":"LoadBalancer works out of the box on bare metal with no extra components."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$LoadBalancer requires a cloud controller or a bare-metal implementation (MetalLB/kube-vip); it is not automatic on bare metal. The layered ClusterIP→NodePort→LoadBalancer model is otherwise correct.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about ClusterIP vs NodePort vs LoadBalancer Services.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$An Ingress resource has no effect unless an Ingress controller is deployed and running in the cluster.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$True. The Ingress API only declares routing intent; an Ingress controller (ingress-nginx, etc.) must watch and program it for traffic to flow.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$An Ingress resource has no effect unless an Ingress controller is deployed and running in the cluster.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command shows why a PVC is stuck Pending?$k8s$, $k8s$[{"id":"a","text":"kubectl describe pvc <name>"},{"id":"b","text":"kubectl logs pvc <name>"},{"id":"c","text":"kubectl top pvc <name>"},{"id":"d","text":"kubectl get sc --pvc <name>"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl describe pvc` surfaces events such as "no persistent volumes available" or provisioning failures — the first step in diagnosing a Pending claim.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command shows why a PVC is stuck Pending?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod must use a volume whose lifecycle is tied to the Pod (deleted when the Pod is removed). Use:$k8s$, $k8s$[{"id":"a","text":"an emptyDir volume"},{"id":"b","text":"a PVC with reclaimPolicy Retain"},{"id":"c","text":"a hostPath volume"},{"id":"d","text":"a static PV"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`emptyDir` is created when the Pod is assigned to a node and deleted when the Pod is removed — ephemeral, Pod-scoped storage (e.g. scratch space, sidecar log sharing).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/volumes/","label":"Kubernetes Docs — Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod must use a volume whose lifecycle is tied to the Pod (deleted when the Pod is removed). Use:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You set a StorageClass as cluster default but PVCs still fail to provision dynamically. A likely cause is:$k8s$, $k8s$[{"id":"a","text":"No provisioner/CSI driver is installed for that StorageClass."},{"id":"b","text":"The PVC requested ReadOnlyMany."},{"id":"c","text":"The Pod has no nodeSelector."},{"id":"d","text":"reclaimPolicy is Delete."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Dynamic provisioning needs a working provisioner (CSI driver/controller) matching the StorageClass `provisioner`. Without it, even a default StorageClass cannot create PVs.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You set a StorageClass as cluster default but PVCs still fail to provision dynamically. A likely cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A PV is `Released` (Retain) and you want to reuse the underlying disk for a fresh PVC. The cleanest approach is:$k8s$, $k8s$[{"id":"a","text":"Delete the PV object and recreate a new PV pointing at the same disk, then bind a new PVC."},{"id":"b","text":"Change the StorageClass."},{"id":"c","text":"Reboot the node."},{"id":"d","text":"Set the PVC to ReadOnlyMany."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A Retain PV stays Released with a stale claimRef. Either clear the claimRef to make it Available, or delete and recreate the PV referencing the same backing storage, then bind a new PVC.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A PV is `Released` (Retain) and you want to reuse the underlying disk for a fresh PVC. The cleanest approach is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Storage$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A StorageClass with `volumeBindingMode: WaitForFirstConsumer` delays PV provisioning until a Pod using the PVC is scheduled.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$True. WaitForFirstConsumer defers binding/provisioning until a consuming Pod is scheduled, enabling topology-aware placement (e.g. for local or zonal volumes).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/storage-classes/","label":"Kubernetes Docs — Storage Classes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A StorageClass with `volumeBindingMode: WaitForFirstConsumer` delays PV provisioning until a Pod using the PVC is scheduled.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command lists all Pods across all namespaces with their status?$k8s$, $k8s$[{"id":"a","text":"kubectl get pods -A"},{"id":"b","text":"kubectl get pods --cluster"},{"id":"c","text":"kubectl describe pods --all"},{"id":"d","text":"kubectl pods list"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl get pods -A` (or `--all-namespaces`) lists every Pod and its phase, the quickest cluster-wide health snapshot during triage.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/reference/kubectl/","label":"Kubernetes Docs — kubectl Reference"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command lists all Pods across all namespaces with their status?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod is `Evicted` with reason "The node was low on resource: ephemeral-storage". The remediation is:$k8s$, $k8s$[{"id":"a","text":"Reduce the Pod's disk usage / add ephemeral-storage limits, or free node disk."},{"id":"b","text":"Increase the memory request."},{"id":"c","text":"Restart kube-proxy."},{"id":"d","text":"Add a toleration."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Ephemeral-storage eviction means node disk pressure. Clean node disk, set sensible ephemeral-storage requests/limits, or move logs/scratch to a volume.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod is `Evicted` with reason "The node was low on resource: ephemeral-storage". The remediation is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$kube-apiserver logs show "etcdserver: request timed out". The MOST likely root cause is:$k8s$, $k8s$[{"id":"a","text":"etcd is unhealthy/slow or unreachable from the apiserver."},{"id":"b","text":"kubectl is misconfigured."},{"id":"c","text":"A NetworkPolicy blocks Pods."},{"id":"d","text":"The Service has no endpoints."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$The apiserver depends on etcd; request timeouts point to etcd being down, slow (disk I/O), or network-unreachable. Check the etcd static Pod, disk latency, and `etcdctl endpoint health`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$kube-apiserver logs show "etcdserver: request timed out". The MOST likely root cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod cannot reach a Service although endpoints exist. Curling the Pod IP directly works. The likely cause is:$k8s$, $k8s$[{"id":"a","text":"kube-proxy is not programming Service rules on that node (check its DaemonSet)."},{"id":"b","text":"The image is wrong."},{"id":"c","text":"The PVC is Pending."},{"id":"d","text":"CoreDNS scaled to zero."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Direct Pod IP works but the Service VIP does not → Service routing (iptables/IPVS) is not programmed, typically a kube-proxy failure on that node. Inspect the kube-proxy DaemonSet/logs.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod cannot reach a Service although endpoints exist. Curling the Pod IP directly works. The likely cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need the last 50 log lines for container `app` in a multi-container Pod. The command is:$k8s$, $k8s$[{"id":"a","text":"kubectl logs <pod> -c app --tail=50"},{"id":"b","text":"kubectl logs <pod> --all-containers --head=50"},{"id":"c","text":"kubectl logs <pod> --previous"},{"id":"d","text":"kubectl describe pod <pod> | tail -50"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$In a multi-container Pod you must select the container with `-c`; `--tail=50` limits the output to the most recent 50 lines.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need the last 50 log lines for container `app` in a multi-container Pod. The command is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A new Pod stays `Pending` and `kubectl describe` shows "untolerated taint" for a DEDICATED workload node. The intended fix is:$k8s$, $k8s$[{"id":"a","text":"Add a matching toleration to the Pod so it can land on the dedicated node."},{"id":"b","text":"Remove all taints cluster-wide."},{"id":"c","text":"Restart the scheduler."},{"id":"d","text":"Use hostNetwork."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$For a deliberately tainted dedicated node, the correct fix is to add the matching toleration to Pods that should run there — not to strip the taint, which would defeat node isolation.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/scheduling-eviction/taint-and-toleration/","label":"Kubernetes Docs — Taints and Tolerations"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A new Pod stays `Pending` and `kubectl describe` shows "untolerated taint" for a DEDICATED workload node. The intended fix is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A worker shows `Ready` but Pods scheduled there never start (stuck ContainerCreating). `crictl ps` is empty. Check first:$k8s$, $k8s$[{"id":"a","text":"The container runtime and CNI on that node (crictl info, CNI Pod logs)."},{"id":"b","text":"The apiserver audit log."},{"id":"c","text":"kubectl version skew."},{"id":"d","text":"The Ingress controller."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$ContainerCreating with no containers usually means the runtime or CNI cannot set up the sandbox. Inspect `crictl info`, containerd status, and the CNI plugin logs on that node.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/extend-kubernetes/compute-storage-net/network-plugins/","label":"Kubernetes Docs — Network Plugins (CNI)"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A worker shows `Ready` but Pods scheduled there never start (stuck ContainerCreating). `crictl ps` is empty. Check first:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$After `kubectl apply`, a Deployment is unchanged and kubectl prints "unchanged". You expected a rollout. The likely reason is:$k8s$, $k8s$[{"id":"a","text":"The applied manifest is identical to the live spec (no diff to trigger a rollout)."},{"id":"b","text":"The apiserver is down."},{"id":"c","text":"RBAC denied the apply."},{"id":"d","text":"The namespace is terminating."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A rollout only happens when the Pod template changes. If `apply` reports "unchanged", the manifest matched the live object; use `kubectl rollout restart` to force a new rollout.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$After `kubectl apply`, a Deployment is unchanged and kubectl prints "unchanged". You expected a rollout. The likely reason is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$etcd is up but `kubectl` commands are very slow cluster-wide. A common root cause to investigate is:$k8s$, $k8s$[{"id":"a","text":"etcd disk latency / fsync performance (slow storage backing /var/lib/etcd)."},{"id":"b","text":"kubectl binary version."},{"id":"c","text":"A missing Service selector."},{"id":"d","text":"The Ingress class."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$etcd is highly sensitive to disk fsync latency. Slow disks cause apiserver/etcd latency that manifests as cluster-wide kubectl slowness. Check etcd metrics and move it to faster storage.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/administer-cluster/configure-upgrade-etcd/","label":"Kubernetes Docs — Operating etcd"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$etcd is up but `kubectl` commands are very slow cluster-wide. A common root cause to investigate is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Job never completes and its Pod is stuck `Pending` with "0/3 nodes are available: insufficient memory". The fix is:$k8s$, $k8s$[{"id":"a","text":"Lower the Job Pod memory request or add node capacity."},{"id":"b","text":"Increase backoffLimit."},{"id":"c","text":"Set restartPolicy: Always."},{"id":"d","text":"Delete CoreDNS."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$"insufficient memory" is a scheduling feasibility problem driven by the Pod's memory request vs node allocatable. Reduce the request or add memory capacity.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Job never completes and its Pod is stuck `Pending` with "0/3 nodes are available: insufficient memory". The fix is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You suspect a control-plane node's kubelet client cert expired. The symptom that fits is:$k8s$, $k8s$[{"id":"a","text":"The node goes NotReady and kubelet logs show TLS/certificate errors talking to the apiserver."},{"id":"b","text":"Pods get more CPU."},{"id":"c","text":"Services lose their cluster IP."},{"id":"d","text":"CoreDNS returns NXDOMAIN for everything."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$An expired kubelet client cert breaks the kubelet→apiserver mTLS, so the node stops heartbeating and goes NotReady with cert errors. Rotate the kubelet cert / re-issue its kubeconfig.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/setup/production-environment/tools/kubeadm/","label":"Kubernetes Docs — kubeadm"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You suspect a control-plane node's kubelet client cert expired. The symptom that fits is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$To create an ephemeral debug container in a running Pod (e.g. to get a shell with tools), use:$k8s$, $k8s$[{"id":"a","text":"kubectl debug -it <pod> --image=busybox --target=<container>"},{"id":"b","text":"kubectl exec -it <pod> --add-tools"},{"id":"c","text":"kubectl run debug --attach"},{"id":"d","text":"kubectl cp tools <pod>:/"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl debug` injects an ephemeral container sharing the target Pod's namespaces, useful when the app image lacks a shell or debugging tools. It does not restart the Pod.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$To create an ephemeral debug container in a running Pod (e.g. to get a shell with tools), use:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Troubleshooting$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A Pod in `CrashLoopBackOff` is repeatedly starting and exiting; the back-off delay between restarts grows over time.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$True. The kubelet applies an exponential back-off (capped) between restarts of a repeatedly failing container, which is why the state is named CrashLoopBackOff.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/debug/debug-cluster/","label":"Kubernetes Docs — Troubleshooting Clusters"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:cka-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKA-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod in `CrashLoopBackOff` is repeatedly starting and exiting; the back-off delay between restarts grows over time.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which `kubectl` command imperatively creates a Pod named `mypod` running the `nginx:1.25` image and exposes container port 80, without creating a Deployment?$k8s$, $k8s$[{"id":"a","text":"kubectl create pod mypod --image=nginx:1.25 --port=80"},{"id":"b","text":"kubectl run mypod --image=nginx:1.25 --restart=Never --port=80"},{"id":"c","text":"kubectl apply pod mypod --image=nginx:1.25 --port=80"},{"id":"d","text":"kubectl deploy mypod --image=nginx:1.25 --port=80"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`kubectl run` with `--restart=Never` creates a bare Pod (not a Deployment or Job). `--port` records the containerPort. `kubectl create pod` is not a valid subcommand, and `kubectl apply` requires a manifest.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which `kubectl` command imperatively creates a Pod named `mypod` running the `nginx:1.25` image and exposes container port 80, without creating a Deployment?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod must run a one-off database migration to completion before the main application container starts and serves traffic. Which Pod construct is the correct fit?$k8s$, $k8s$[{"id":"a","text":"A sidecar container in the same Pod"},{"id":"b","text":"An initContainer that runs the migration"},{"id":"c","text":"A separate Deployment running the migration script"},{"id":"d","text":"A liveness probe that triggers the migration"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Init containers run to completion sequentially before any app containers start. Sidecars run alongside app containers (not before), and probes do not run workloads.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod must run a one-off database migration to completion before the main application container starts and serves traffic. Which Pod construct is the correct fit?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$You need a workload that runs to completion on a schedule every night at 02:00. Select ALL true statements about Kubernetes CronJobs.$k8s$, $k8s$[{"id":"a","text":"CronJob.spec.schedule uses standard cron syntax (e.g. \"0 2 * * *\")."},{"id":"b","text":"A CronJob creates a Job object for each scheduled run."},{"id":"c","text":"CronJobs run forever; like Deployments they restart Pods on completion."},{"id":"d","text":"spec.concurrencyPolicy can be Allow, Forbid, or Replace."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$CronJobs spawn a Job per schedule fire. Jobs run to completion — CronJobs do NOT restart finished Pods like Deployments. `concurrencyPolicy` controls overlapping runs.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/","label":"Kubernetes Docs — CronJobs"},{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need a workload that runs to completion on a schedule every night at 02:00. Select ALL true statements about Kubernetes CronJobs.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$You build a container image and the running container exits immediately. The Dockerfile ends with `CMD ["./app"]` but a `kubectl logs` shows "exec: ./app: not found". The most likely cause is:$k8s$, $k8s$[{"id":"a","text":"The image uses a scratch base and the binary is dynamically linked against glibc that is not present."},{"id":"b","text":"The Pod has no readiness probe configured."},{"id":"c","text":"The Service selector does not match the Pod labels."},{"id":"d","text":"A NetworkPolicy is blocking the container from starting."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A dynamically linked binary placed in a scratch image fails to exec because the dynamic loader/glibc is absent. Probes, Services, and NetworkPolicies are unrelated to container startup exec failures.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You build a container image and the running container exits immediately. The Dockerfile ends with `CMD ["./app"]` but a `kubectl logs` shows "exec: ./app: not found". The most likely cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$You need to update the image of Deployment `web` to `nginx:1.27` while preserving rollout history. Which command does this idiomatically?$k8s$, $k8s$[{"id":"a","text":"kubectl edit deployment web (and save the file)"},{"id":"b","text":"kubectl set image deployment/web nginx=nginx:1.27"},{"id":"c","text":"kubectl replace deployment/web --image=nginx:1.27"},{"id":"d","text":"kubectl patch pod web --image=nginx:1.27"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`kubectl set image` is the canonical, recorded way to update a container image on a Deployment and triggers a rolling update with a revision recorded in the rollout history.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need to update the image of Deployment `web` to `nginx:1.27` while preserving rollout history. Which command does this idiomatically?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A bad image was rolled out to Deployment `api`. Which command rolls back to the previous revision?$k8s$, $k8s$[{"id":"a","text":"kubectl undo deployment api"},{"id":"b","text":"kubectl rollout undo deployment/api"},{"id":"c","text":"kubectl rollback deployment api --to-revision=previous"},{"id":"d","text":"kubectl rollout revert deployment/api"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`kubectl rollout undo deployment/<name>` reverts to the prior revision. Use `--to-revision=N` to target a specific one.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A bad image was rolled out to Deployment `api`. Which command rolls back to the previous revision?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$In a Deployment's RollingUpdate strategy, `maxSurge: 25%` and `maxUnavailable: 0` for a 4-replica Deployment means:$k8s$, $k8s$[{"id":"a","text":"At most 1 extra Pod above 4 may exist during rollout; never fewer than 4 ready."},{"id":"b","text":"Up to 25% of Pods may be unavailable at any time."},{"id":"c","text":"Pods are upgraded one at a time, terminating the old first."},{"id":"d","text":"The Deployment is paused until all Pods are ready."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`maxSurge` is how many Pods above desired may be created during rollout. `maxUnavailable: 0` means the ready count never drops below desired — useful for zero-downtime updates.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$In a Deployment's RollingUpdate strategy, `maxSurge: 25%` and `maxUnavailable: 0` for a 4-replica Deployment means:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which tool packages Kubernetes manifests as versioned, templatable units called "charts" with values overrides?$k8s$, $k8s$[{"id":"a","text":"Kustomize"},{"id":"b","text":"Helm"},{"id":"c","text":"Skaffold"},{"id":"d","text":"kubectl apply -k"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Helm uses charts and a `values.yaml` template system. Kustomize composes overlays from base manifests without templating.$k8s$, $k8s$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which tool packages Kubernetes manifests as versioned, templatable units called "charts" with values overrides?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Your app boots in 45 seconds before its `/healthz` endpoint becomes responsive. The kubelet keeps killing the Pod with "Liveness probe failed". The MOST appropriate fix is:$k8s$, $k8s$[{"id":"a","text":"Remove the liveness probe entirely."},{"id":"b","text":"Add a startupProbe so the liveness probe is suppressed until the container has finished starting."},{"id":"c","text":"Replace the liveness probe with a readiness probe."},{"id":"d","text":"Increase the Pod's memory limit."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$startupProbe lets slow-starting containers boot without being killed by liveness. Replacing liveness with readiness leaves the Pod running but never marked ready, hurting traffic. Removing liveness entirely is not recommended for long-lived processes.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Your app boots in 45 seconds before its `/healthz` endpoint becomes responsive. The kubelet keeps killing the Pod with "Liveness probe failed". The MOST appropriate fix is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Pod `web-7d8` is in a `CrashLoopBackOff`. Which sequence is the BEST first-step diagnosis?$k8s$, $k8s$[{"id":"a","text":"kubectl delete pod web-7d8 and let it be recreated."},{"id":"b","text":"kubectl logs web-7d8 --previous; kubectl describe pod web-7d8"},{"id":"c","text":"kubectl exec -it web-7d8 -- /bin/sh"},{"id":"d","text":"kubectl scale deployment web --replicas=0 then back up."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`logs --previous` shows stdout of the crashed container before restart; `describe` shows Events and exit codes. Exec only works on a running container.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Pod `web-7d8` is in a `CrashLoopBackOff`. Which sequence is the BEST first-step diagnosis?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about probes in Kubernetes.$k8s$, $k8s$[{"id":"a","text":"A failing readinessProbe removes the Pod's IP from Service endpoints but does NOT restart the container."},{"id":"b","text":"A failing livenessProbe causes the kubelet to restart the container."},{"id":"c","text":"A startupProbe runs continuously throughout the Pod's lifetime."},{"id":"d","text":"Probes can be httpGet, exec, tcpSocket, or grpc actions."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$startupProbe runs ONLY during startup, then liveness/readiness take over. Readiness gates traffic without restart; liveness triggers restart. Probe actions are httpGet/exec/tcpSocket/grpc.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about probes in Kubernetes.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command creates a ConfigMap named `app-config` containing a single key `LOG_LEVEL=debug` imperatively?$k8s$, $k8s$[{"id":"a","text":"kubectl create configmap app-config --from-literal=LOG_LEVEL=debug"},{"id":"b","text":"kubectl set configmap app-config LOG_LEVEL=debug"},{"id":"c","text":"kubectl run configmap app-config --env=LOG_LEVEL=debug"},{"id":"d","text":"kubectl apply configmap app-config --data=LOG_LEVEL=debug"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`--from-literal=KEY=VALUE` is the standard way to inject literal key/value pairs into a ConfigMap. `--from-file=` loads file contents instead.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command creates a ConfigMap named `app-config` containing a single key `LOG_LEVEL=debug` imperatively?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need a Pod that runs as a NON-root user with UID 1000 and rejects privilege escalation. Which `securityContext` fragment achieves this?$k8s$, $k8s$[{"id":"a","text":"spec.securityContext: { runAsUser: 1000, allowPrivilegeEscalation: false }"},{"id":"b","text":"spec.securityContext: { runAsUser: 1000 } and spec.containers[].securityContext: { allowPrivilegeEscalation: false }"},{"id":"c","text":"spec.containers[].env: { USER: \"1000\", PRIV_ESCAL: \"false\" }"},{"id":"d","text":"spec.serviceAccountName: non-root"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`runAsUser` is valid at Pod or container level. `allowPrivilegeEscalation` is a CONTAINER-level field only and must be set in the container's securityContext.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need a Pod that runs as a NON-root user with UID 1000 and rejects privilege escalation. Which `securityContext` fragment achieves this?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$How are Secret values stored in etcd by default in a managed Kubernetes cluster with default settings?$k8s$, $k8s$[{"id":"a","text":"AES-256 encrypted at rest with a customer-managed key."},{"id":"b","text":"Base64-encoded (NOT encrypted) unless an EncryptionConfiguration is configured."},{"id":"c","text":"Hashed with bcrypt."},{"id":"d","text":"Stored only on the kubelet node, never in etcd."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$By default, Kubernetes Secrets are base64-encoded in etcd — encoding, NOT encryption. Encryption-at-rest requires `EncryptionConfiguration` on the API server.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$How are Secret values stored in etcd by default in a managed Kubernetes cluster with default settings?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod needs to call the Kubernetes API to list Pods in its namespace. Which is the correct approach?$k8s$, $k8s$[{"id":"a","text":"Hard-code an admin kubeconfig as a Secret in the Pod."},{"id":"b","text":"Create a ServiceAccount with a Role granting `get,list pods`, bind it via RoleBinding, and set `spec.serviceAccountName` on the Pod."},{"id":"c","text":"Set `spec.privileged: true` on the container."},{"id":"d","text":"Disable RBAC for the namespace."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$The correct pattern is a dedicated ServiceAccount bound to a least-privilege Role via a RoleBinding. The Pod uses that SA via `spec.serviceAccountName`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/","label":"Kubernetes Docs — ServiceAccounts"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod needs to call the Kubernetes API to list Pods in its namespace. Which is the correct approach?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A container requests 100m CPU and limits 500m CPU. The node has free capacity. During traffic spikes the container is throttled at ~500m even though there is idle CPU. Why?$k8s$, $k8s$[{"id":"a","text":"The request, not the limit, caps usage."},{"id":"b","text":"The CPU LIMIT enforces a hard cap via CFS quota — usage above 500m is throttled regardless of node capacity."},{"id":"c","text":"The kubelet evicts the Pod above 500m CPU."},{"id":"d","text":"Throttling occurs only when memory pressure exists."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$CPU `limits` are enforced as hard CFS quotas — a container is throttled at the limit even when the node is idle. `requests` only affect scheduling.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A container requests 100m CPU and limits 500m CPU. The node has free capacity. During traffic spikes the container is throttled at ~500m even though there is idle CPU. Why?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which Service type exposes a Pod set on a stable cluster-internal IP only?$k8s$, $k8s$[{"id":"a","text":"NodePort"},{"id":"b","text":"LoadBalancer"},{"id":"c","text":"ClusterIP"},{"id":"d","text":"ExternalName"}]$k8s$::jsonb, $k8s$["c"]$k8s$::jsonb, $k8s$ClusterIP (the default) is internal-only. NodePort opens a port on every node; LoadBalancer provisions an external LB; ExternalName is a DNS alias.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which Service type exposes a Pod set on a stable cluster-internal IP only?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Service `db.production` is reached from a Pod in the `production` namespace via which fully qualified DNS name?$k8s$, $k8s$[{"id":"a","text":"db"},{"id":"b","text":"db.svc.production"},{"id":"c","text":"db.production.svc.cluster.local"},{"id":"d","text":"production.db.cluster.local"}]$k8s$::jsonb, $k8s$["c"]$k8s$::jsonb, $k8s$Service DNS is `<svc>.<ns>.svc.cluster.local`. Within the same namespace `db` alone resolves; the FQDN is `db.production.svc.cluster.local`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Service `db.production` is reached from a Pod in the `production` namespace via which fully qualified DNS name?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$About Kubernetes NetworkPolicies, select ALL true statements.$k8s$, $k8s$[{"id":"a","text":"A NetworkPolicy needs a CNI plugin that implements policy enforcement (e.g. Calico, Cilium) to take effect."},{"id":"b","text":"In a namespace with NO NetworkPolicy, all Pod-to-Pod traffic is allowed by default."},{"id":"c","text":"A NetworkPolicy selecting Pods with no `ingress` rules denies ALL ingress to those Pods."},{"id":"d","text":"NetworkPolicies can filter by destination port AND by source Pod labels."}]$k8s$::jsonb, $k8s$["a","b","c","d"]$k8s$::jsonb, $k8s$All four are true. The default cluster posture is allow-all until a NetworkPolicy targets a Pod; once targeted, traffic must match an explicit allow rule.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$About Kubernetes NetworkPolicies, select ALL true statements.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need to expose HTTP path `/api/*` of Service `api` and `/web/*` of Service `web` on the same external hostname. The correct resource is:$k8s$, $k8s$[{"id":"a","text":"Two LoadBalancer Services on the same external IP"},{"id":"b","text":"An Ingress with two path rules pointing to the two Services"},{"id":"c","text":"A NodePort Service with multiple ports"},{"id":"d","text":"A NetworkPolicy with two egress rules"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Ingress provides HTTP host- and path-based routing to multiple backend Services through a single ingress controller.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need to expose HTTP path `/api/*` of Service `api` and `/web/*` of Service `web` on the same external hostname. The correct resource is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command generates a Pod manifest to stdout WITHOUT creating the Pod, useful for editing before applying?$k8s$, $k8s$[{"id":"a","text":"kubectl run nginx --image=nginx --dry-run=client -o yaml"},{"id":"b","text":"kubectl create pod nginx --image=nginx --no-apply"},{"id":"c","text":"kubectl generate pod nginx --image=nginx"},{"id":"d","text":"kubectl run nginx --image=nginx --export"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`--dry-run=client -o yaml` renders the manifest locally without contacting the server, the standard recipe for scaffolding a YAML to edit. `--export` was removed and `kubectl generate` does not exist.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command generates a Pod manifest to stdout WITHOUT creating the Pod, useful for editing before applying?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod uses the ambassador pattern. What does the ambassador container do?$k8s$, $k8s$[{"id":"a","text":"Runs the migration before the app starts."},{"id":"b","text":"Proxies outbound network connections (e.g. to a sharded database) so the main container talks only to localhost."},{"id":"c","text":"Transforms the app's log format for an external monitoring system."},{"id":"d","text":"Holds the Pod's shared volume open."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$The ambassador pattern places a proxy sidecar that brokers connections to external services, letting the main container use a simple localhost endpoint while the ambassador handles discovery/sharding/TLS.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/#workload-resources-for-managing-pods","label":"Kubernetes Docs — Pod Design Patterns"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod uses the ambassador pattern. What does the ambassador container do?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A Job with `restartPolicy: Always` is valid in its Pod template.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Job Pod templates must use `restartPolicy: OnFailure` or `Never`. `Always` is rejected because a Job must be able to reach a terminal completed state.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Job with `restartPolicy: Always` is valid in its Pod template.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You want a Job whose Pods are cleaned up automatically 100 seconds after the Job finishes. Which field do you set?$k8s$, $k8s$[{"id":"a","text":"spec.ttlSecondsAfterFinished: 100"},{"id":"b","text":"spec.activeDeadlineSeconds: 100"},{"id":"c","text":"spec.backoffLimit: 100"},{"id":"d","text":"spec.completions: 100"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`ttlSecondsAfterFinished` lets the TTL controller delete a finished Job (and its Pods) after the given seconds. `activeDeadlineSeconds` caps runtime, not cleanup.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You want a Job whose Pods are cleaned up automatically 100 seconds after the Job finishes. Which field do you set?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A multi-stage Dockerfile copies a compiled binary from a `builder` stage into a minimal final image. The primary benefit is:$k8s$, $k8s$[{"id":"a","text":"Faster CPU at runtime."},{"id":"b","text":"A smaller final image with no build toolchain, reducing attack surface and pull time."},{"id":"c","text":"Automatic horizontal scaling."},{"id":"d","text":"Built-in liveness probing."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Multi-stage builds discard compilers and intermediate artifacts, shipping only the runtime artifact. This shrinks the image and removes unneeded tools from the attack surface.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A multi-stage Dockerfile copies a compiled binary from a `builder` stage into a minimal final image. The primary benefit is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which Pod field guarantees an init container completes before a sidecar (native sidecar) and the main app start?$k8s$, $k8s$[{"id":"a","text":"A regular initContainer entry (without restartPolicy) listed before the native sidecar."},{"id":"b","text":"A container in spec.containers with a higher priority."},{"id":"c","text":"spec.terminationGracePeriodSeconds."},{"id":"d","text":"An emptyDir volume."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Ordinary init containers (no `restartPolicy: Always`) run to completion sequentially before any sidecar or app container starts. Native sidecars are init containers WITH `restartPolicy: Always` and stay running.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which Pod field guarantees an init container completes before a sidecar (native sidecar) and the main app start?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL valid reasons to put two containers in the SAME Pod rather than two Pods.$k8s$, $k8s$[{"id":"a","text":"They must share the same network namespace (localhost) and lifecycle."},{"id":"b","text":"They need to share an emptyDir volume tightly coupled to the app."},{"id":"c","text":"They should scale independently of each other."},{"id":"d","text":"One adapts/proxies for the other (sidecar/adapter/ambassador)."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$Co-locating is right for tightly coupled helpers sharing network/volumes/lifecycle. If two components must scale independently, they belong in separate Pods/Deployments.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/#workload-resources-for-managing-pods","label":"Kubernetes Docs — Pod Design Patterns"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL valid reasons to put two containers in the SAME Pod rather than two Pods.$k8s$);
