INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You change a Deployment's `spec.template` annotation only (no image change). What happens?$k8s$, $k8s$[{"id":"a","text":"Nothing — only image changes trigger rollouts."},{"id":"b","text":"A new ReplicaSet is created and a rolling update occurs because the Pod template hash changed."},{"id":"c","text":"The Deployment is rejected."},{"id":"d","text":"Existing Pods are patched in place without restart."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Any change to `spec.template` (including labels/annotations on the Pod template) changes the template hash, creating a new ReplicaSet and triggering a rolling update.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You change a Deployment's `spec.template` annotation only (no image change). What happens?$k8s$);
