INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment has `minReadySeconds: 20`. During a rolling update, a new Pod becomes Ready. When is it counted as available?$k8s$, $k8s$[{"id":"a","text":"Immediately when Ready."},{"id":"b","text":"Only after it has been Ready for 20 continuous seconds."},{"id":"c","text":"After 20 seconds regardless of Ready state."},{"id":"d","text":"Never — minReadySeconds blocks the rollout."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`minReadySeconds` requires a Pod to stay Ready for that duration before it is considered available, slowing rollouts so flapping Pods are not counted as healthy.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment has `minReadySeconds: 20`. During a rolling update, a new Pod becomes Ready. When is it counted as available?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Helm: which command upgrades a release `myapp` with a new chart version and overridden value `replicaCount=4`?$k8s$, $k8s$[{"id":"a","text":"helm upgrade myapp ./chart --set replicaCount=4"},{"id":"b","text":"helm update myapp --replicas=4"},{"id":"c","text":"helm install myapp ./chart --upgrade --replicaCount 4"},{"id":"d","text":"helm patch myapp replicaCount=4"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`helm upgrade <release> <chart> --set key=value` upgrades an existing release with overrides. `--set` overrides values inline; `-f` supplies a values file.$k8s$, $k8s$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Helm: which command upgrades a release `myapp` with a new chart version and overridden value `replicaCount=4`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Kustomize: which kubectl command applies a kustomization in the current directory?$k8s$, $k8s$[{"id":"a","text":"kubectl apply -k ."},{"id":"b","text":"kubectl kustomize apply ."},{"id":"c","text":"kubectl apply --kustomize-build ."},{"id":"d","text":"kubectl apply -f kustomization.yaml"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl apply -k <dir>` builds the kustomization (base + overlays/patches) and applies the result. `kubectl kustomize <dir>` only renders to stdout.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Kustomize: which kubectl command applies a kustomization in the current directory?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which probe should you use to delay traffic to a Pod until it has loaded its cache, WITHOUT restarting the container if loading is slow?$k8s$, $k8s$[{"id":"a","text":"livenessProbe"},{"id":"b","text":"readinessProbe"},{"id":"c","text":"startupProbe"},{"id":"d","text":"A preStop hook"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Readiness gates Service traffic without restarting the container. Liveness restarts on failure; startupProbe protects slow boots from liveness but does not itself gate Service endpoints the way readiness does.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which probe should you use to delay traffic to a Pod until it has loaded its cache, WITHOUT restarting the container if loading is slow?$k8s$);
