INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command creates a TLS Secret from cert and key files?$k8s$, $k8s$[{"id":"a","text":"kubectl create secret tls my-tls --cert=tls.crt --key=tls.key"},{"id":"b","text":"kubectl create secret generic my-tls --tls --cert tls.crt"},{"id":"c","text":"kubectl create tls my-tls tls.crt tls.key"},{"id":"d","text":"kubectl create secret my-tls --type=tls"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl create secret tls <name> --cert= --key=` produces a `kubernetes.io/tls` Secret containing `tls.crt` and `tls.key`, suitable for Ingress TLS.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command creates a TLS Secret from cert and key files?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about resource requests and limits.$k8s$, $k8s$[{"id":"a","text":"Scheduling decisions are based on requests, not limits."},{"id":"b","text":"A container exceeding its memory limit is OOMKilled."},{"id":"c","text":"A container exceeding its CPU limit is OOMKilled."},{"id":"d","text":"If requests == limits for all resources, the Pod gets the Guaranteed QoS class."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$CPU is compressible: exceeding the CPU limit causes throttling, NOT OOMKill. Memory is incompressible: exceeding the memory limit triggers OOMKill. Requests drive scheduling and QoS classification.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about resource requests and limits.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod needs an emptyDir that lives in RAM (tmpfs) for fast scratch I/O. Which spec achieves this?$k8s$, $k8s$[{"id":"a","text":"volumes: [{ name: cache, emptyDir: { medium: Memory } }]"},{"id":"b","text":"volumes: [{ name: cache, emptyDir: { type: tmpfs } }]"},{"id":"c","text":"volumes: [{ name: cache, ramDisk: {} }]"},{"id":"d","text":"volumes: [{ name: cache, hostPath: { path: /dev/shm } }]"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`emptyDir.medium: Memory` backs the volume with tmpfs (RAM). It counts against the container's memory limit and is cleared when the Pod is removed.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod needs an emptyDir that lives in RAM (tmpfs) for fast scratch I/O. Which spec achieves this?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You want a PVC of 5Gi that is dynamically provisioned by the `fast-ssd` StorageClass. Which fields are required on the PVC?$k8s$, $k8s$[{"id":"a","text":"spec.storageClassName: fast-ssd, spec.accessModes, spec.resources.requests.storage: 5Gi"},{"id":"b","text":"spec.volumeName: fast-ssd only"},{"id":"c","text":"spec.capacity.storage: 5Gi only"},{"id":"d","text":"spec.provisioner: fast-ssd"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A dynamically provisioned PVC needs a `storageClassName`, `accessModes`, and a storage request. `provisioner` is a StorageClass field, and `capacity` is a PV field.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You want a PVC of 5Gi that is dynamically provisioned by the `fast-ssd` StorageClass. Which fields are required on the PVC?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command exposes Deployment `web` as a ClusterIP Service on port 80 targeting container port 8080?$k8s$, $k8s$[{"id":"a","text":"kubectl expose deployment web --port=80 --target-port=8080"},{"id":"b","text":"kubectl service create web --port=80 --container=8080"},{"id":"c","text":"kubectl expose deployment web --listen=80 --forward=8080"},{"id":"d","text":"kubectl create svc web 80:8080"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl expose deployment <name> --port= --target-port=` creates a Service (ClusterIP by default) whose `port` is the Service port and `targetPort` the container port.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command exposes Deployment `web` as a ClusterIP Service on port 80 targeting container port 8080?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A headless Service has `clusterIP: None`. What is its effect for a backing StatefulSet?$k8s$, $k8s$[{"id":"a","text":"It load-balances over a single virtual IP."},{"id":"b","text":"DNS returns the individual Pod IPs (and per-Pod DNS names) instead of one virtual IP."},{"id":"c","text":"It blocks all traffic."},{"id":"d","text":"It exposes the Service on every node."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$A headless Service (`clusterIP: None`) skips the virtual IP; DNS returns the Pod A records directly, enabling per-Pod addressing for StatefulSets.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A headless Service has `clusterIP: None`. What is its effect for a backing StatefulSet?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Service maps `port: 80` to `targetPort: http`. What must the Pod define for this to resolve?$k8s$, $k8s$[{"id":"a","text":"A named container port `http` in containers[].ports."},{"id":"b","text":"An env var named http."},{"id":"c","text":"A label http=true."},{"id":"d","text":"An annotation port/http."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A string `targetPort` references a container port by its `name`. The Pod must declare `ports: [{ name: http, containerPort: <n> }]` so the Service can resolve it.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Service maps `port: 80` to `targetPort: http`. What must the Pod define for this to resolve?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A NetworkPolicy that specifies an `egress` rule restricts only outbound traffic from the selected Pods and does not by itself affect inbound traffic.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Ingress and egress are independent in a NetworkPolicy. Declaring `policyTypes: [Egress]` with egress rules constrains outbound traffic only; ingress remains governed by other policies (or default-allow).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A NetworkPolicy that specifies an `egress` rule restricts only outbound traffic from the selected Pods and does not by itself affect inbound traffic.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$Two NetworkPolicies select the same Pod: one allows ingress from `app=a`, another from `app=b`. The effective ingress allow set is:$k8s$, $k8s$[{"id":"a","text":"Only app=a (first policy wins)."},{"id":"b","text":"The UNION — traffic from app=a OR app=b is allowed."},{"id":"c","text":"The intersection — only Pods that are both app=a and app=b."},{"id":"d","text":"Nothing — conflicting policies deny all."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$NetworkPolicies are additive. When multiple policies select a Pod, the allowed traffic is the union of all their rules; there is no deny rule and no precedence.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Two NetworkPolicies select the same Pod: one allows ingress from `app=a`, another from `app=b`. The effective ingress allow set is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$An Ingress needs path `/v2` to route to `api-v2:80`. Which `pathType` matches `/v2` and `/v2/users` but NOT `/v20`?$k8s$, $k8s$[{"id":"a","text":"Exact"},{"id":"b","text":"Prefix"},{"id":"c","text":"ImplementationSpecific"},{"id":"d","text":"Regex"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`pathType: Prefix` matches by URL path SEGMENTS, so `/v2` matches `/v2` and `/v2/users` but not `/v20`. `Exact` matches only `/v2` literally.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$An Ingress needs path `/v2` to route to `api-v2:80`. Which `pathType` matches `/v2` and `/v2/users` but NOT `/v20`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A client Pod cannot resolve `web.default.svc.cluster.local`. Which component is responsible for in-cluster Service DNS?$k8s$, $k8s$[{"id":"a","text":"CoreDNS (the cluster DNS add-on)"},{"id":"b","text":"kube-proxy"},{"id":"c","text":"The Ingress controller"},{"id":"d","text":"etcd"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$CoreDNS serves cluster DNS, resolving Service and Pod names. kube-proxy programs the data path (iptables/IPVS) but does not answer DNS queries.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A client Pod cannot resolve `web.default.svc.cluster.local`. Which component is responsible for in-cluster Service DNS?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Service of type LoadBalancer in a cloud cluster also implicitly allocates which other Service primitives?$k8s$, $k8s$[{"id":"a","text":"A ClusterIP and a NodePort, in addition to the external LB."},{"id":"b","text":"Only an ExternalName."},{"id":"c","text":"Nothing else; just the LB."},{"id":"d","text":"An Ingress object."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A LoadBalancer Service is layered on top of NodePort and ClusterIP: it gets a ClusterIP, a NodePort on each node, and the cloud LB forwards to the NodePort.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Service of type LoadBalancer in a cloud cluster also implicitly allocates which other Service primitives?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about Services and selectors.$k8s$, $k8s$[{"id":"a","text":"A Service with no selector will not auto-populate Endpoints; you can manage Endpoints/EndpointSlices manually."},{"id":"b","text":"sessionAffinity: ClientIP pins a client to the same backend Pod."},{"id":"c","text":"A Service selector must match the Deployment's name."},{"id":"d","text":"Removing the only Ready Pod leaves the Service with zero endpoints, so connections fail."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$Selectors match Pod LABELS, not Deployment names. Selector-less Services support manual Endpoints. `sessionAffinity: ClientIP` provides client stickiness. No Ready Pods means no endpoints and failed connections.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P1$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about Services and selectors.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod has one main container plus a small companion container that ships its stdout logs to an external aggregator. This is which multi-container pattern?$k8s$, $k8s$[{"id":"a","text":"Init container"},{"id":"b","text":"Sidecar"},{"id":"c","text":"Ambassador"},{"id":"d","text":"Adapter"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$A sidecar augments the main container (logging, metrics, sync) sharing the same Pod's lifecycle and volumes. Ambassador proxies network calls; adapter normalizes output for external consumption.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/#workload-resources-for-managing-pods","label":"Kubernetes Docs — Pod Design Patterns"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod has one main container plus a small companion container that ships its stdout logs to an external aggregator. This is which multi-container pattern?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You want a Job that runs 5 Pods in parallel until 10 successful completions are reached. Which Job fields achieve this?$k8s$, $k8s$[{"id":"a","text":"completions: 10, parallelism: 5"},{"id":"b","text":"replicas: 10, parallelism: 5"},{"id":"c","text":"completions: 5, parallelism: 10"},{"id":"d","text":"backoffLimit: 10, parallelism: 5"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`completions` is total successes needed; `parallelism` caps concurrent Pods. `backoffLimit` only governs retry attempts on failure.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You want a Job that runs 5 Pods in parallel until 10 successful completions are reached. Which Job fields achieve this?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A CronJob has `concurrencyPolicy: Forbid` and `startingDeadlineSeconds: 30`. The previous run is still active when the next schedule fires 30s late. What happens to that fire?$k8s$, $k8s$[{"id":"a","text":"A second Job is started in parallel."},{"id":"b","text":"The fire is skipped because the previous run is active AND the deadline has passed."},{"id":"c","text":"The previous Job is killed and replaced."},{"id":"d","text":"The CronJob is suspended automatically."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`Forbid` prevents concurrency, and missing the startingDeadline marks the fire as missed/skipped (recorded in status).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/","label":"Kubernetes Docs — CronJobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A CronJob has `concurrencyPolicy: Forbid` and `startingDeadlineSeconds: 30`. The previous run is still active when the next schedule fires 30s late. What happens to that fire?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$In a Dockerfile, which instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT and is preferred over `RUN cd /app`?$k8s$, $k8s$[{"id":"a","text":"CHDIR /app"},{"id":"b","text":"WORKDIR /app"},{"id":"c","text":"PWD /app"},{"id":"d","text":"CD /app"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`WORKDIR` is the only Dockerfile instruction that persists the working directory across layers. `RUN cd` only affects the single layer.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$In a Dockerfile, which instruction sets the working directory for subsequent RUN/CMD/ENTRYPOINT and is preferred over `RUN cd /app`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command scales Deployment `api` to 6 replicas?$k8s$, $k8s$[{"id":"a","text":"kubectl scale deployment/api --replicas=6"},{"id":"b","text":"kubectl resize deployment api 6"},{"id":"c","text":"kubectl set replicas deployment/api 6"},{"id":"d","text":"kubectl deploy api --scale=6"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl scale` is the canonical command for adjusting replicas on Deployments, ReplicaSets, ReplicationControllers, and StatefulSets.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command scales Deployment `api` to 6 replicas?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You apply a Deployment with `strategy.type: Recreate`. What is the practical effect during an update?$k8s$, $k8s$[{"id":"a","text":"New Pods are gradually scaled up while old ones scale down."},{"id":"b","text":"All old Pods are terminated FIRST; then new Pods are created — service downtime is expected."},{"id":"c","text":"Only one Pod is updated at a time."},{"id":"d","text":"The rollout is paused until manual approval."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Recreate fully drains the old Pods before launching the new ones. It is appropriate for workloads incompatible with running two versions simultaneously (e.g. some PVC-bound singletons).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You apply a Deployment with `strategy.type: Recreate`. What is the practical effect during an update?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A canary release strategy on Kubernetes typically:$k8s$, $k8s$[{"id":"a","text":"Replaces all Pods with the new version at once."},{"id":"b","text":"Routes a small share of traffic to a small subset of new-version Pods, expanding as confidence grows."},{"id":"c","text":"Requires the kube-apiserver to be restarted."},{"id":"d","text":"Is only possible with a service mesh."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Canary = gradual exposure of the new version to a subset of users. Achievable natively via two Deployments behind one Service or with finer-grained traffic split via Ingress/Service mesh.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A canary release strategy on Kubernetes typically:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Kustomize's primary value proposition relative to Helm is:$k8s$, $k8s$[{"id":"a","text":"Built-in template language with conditionals and loops."},{"id":"b","text":"Pure-YAML overlays that patch a common \"base\" — no templating language needed."},{"id":"c","text":"A chart registry for versioned releases."},{"id":"d","text":"It replaces kubectl entirely."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Kustomize composes overlays over a base via strategic-merge or JSON patches — there is no template language. Helm offers templating + a chart registry; the two tools are complementary.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Kustomize's primary value proposition relative to Helm is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command tails (streams) logs of all Pods of Deployment `web`?$k8s$, $k8s$[{"id":"a","text":"kubectl logs -f -l app=web"},{"id":"b","text":"kubectl tail deployment/web"},{"id":"c","text":"kubectl logs deployment/web --stream"},{"id":"d","text":"kubectl stream deployment web"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`-l` filters by label and `-f` follows logs. `kubectl logs deployment/web -f` works too but only streams from one Pod selected by the controller.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command tails (streams) logs of all Pods of Deployment `web`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$An exec liveness probe `cat /tmp/healthy` runs every 10s with failureThreshold 3. The file disappears at t=0. Approximately when will the kubelet restart the container?$k8s$, $k8s$[{"id":"a","text":"Immediately at t=0"},{"id":"b","text":"Around t=10s (1 failure)"},{"id":"c","text":"Around t=30s (3 consecutive failures × 10s period)"},{"id":"d","text":"Never — exec probes do not trigger restarts"}]$k8s$::jsonb, $k8s$["c"]$k8s$::jsonb, $k8s$Liveness probes mark a container failed only after `failureThreshold` consecutive failures. With period 10s × 3 failures ≈ 30s before restart.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$An exec liveness probe `cat /tmp/healthy` runs every 10s with failureThreshold 3. The file disappears at t=0. Approximately when will the kubelet restart the container?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which command shows recent cluster events, ordered by timestamp, namespace-scoped?$k8s$, $k8s$[{"id":"a","text":"kubectl get events --sort-by=.lastTimestamp"},{"id":"b","text":"kubectl describe events"},{"id":"c","text":"kubectl event log"},{"id":"d","text":"kubectl logs events"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl get events --sort-by=.lastTimestamp` is the standard debugging recipe. `describe pod` also surfaces the events for a specific Pod.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command shows recent cluster events, ordered by timestamp, namespace-scoped?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You mount a ConfigMap `app-cfg` as a volume at `/etc/app`. The ConfigMap is then updated with `kubectl apply`. What does the running Pod see?$k8s$, $k8s$[{"id":"a","text":"The file in /etc/app is updated automatically after the kubelet sync (eventually consistent; typically within ~1 minute)."},{"id":"b","text":"The Pod is restarted automatically on the next sync."},{"id":"c","text":"Nothing changes until the Pod is manually deleted/recreated."},{"id":"d","text":"The Pod immediately enters CrashLoopBackOff."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$ConfigMaps and Secrets mounted as volumes propagate updates to the in-Pod filesystem on the next kubelet sync (period configurable, default ~60s). Env-var injections, by contrast, are baked in at Pod start.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You mount a ConfigMap `app-cfg` as a volume at `/etc/app`. The ConfigMap is then updated with `kubectl apply`. What does the running Pod see?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$A Secret of type `kubernetes.io/dockerconfigjson` is referenced by a Pod via `spec.imagePullSecrets`. Its purpose is:$k8s$, $k8s$[{"id":"a","text":"Encrypting traffic between Pods."},{"id":"b","text":"Providing credentials to pull images from a private registry."},{"id":"c","text":"Encrypting volumes at rest."},{"id":"d","text":"Authenticating the Pod to the API server."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`dockerconfigjson` secrets carry registry credentials; referenced via `imagePullSecrets`, they let the kubelet pull from private registries.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Secret of type `kubernetes.io/dockerconfigjson` is referenced by a Pod via `spec.imagePullSecrets`. Its purpose is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A namespace has a `ResourceQuota` of `requests.cpu: 1` and `limits.cpu: 2`. You apply a Pod requesting 600m CPU and limiting 1500m. The cluster has free capacity. What happens?$k8s$, $k8s$[{"id":"a","text":"The Pod is accepted because the cluster has free CPU."},{"id":"b","text":"The Pod is REJECTED at admission because limits.cpu (1500m) added to existing usage may exceed 2 (depends on existing usage); but the request also pushes near the 1 CPU ceiling — admission rejects when the quota is exceeded."},{"id":"c","text":"The Pod is accepted but throttled to 100m."},{"id":"d","text":"The kubelet evicts an existing Pod to make room."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$ResourceQuotas are enforced at admission. New Pods are rejected if their request/limit pushes the namespace totals above the quota.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A namespace has a `ResourceQuota` of `requests.cpu: 1` and `limits.cpu: 2`. You apply a Pod requesting 600m CPU and limiting 1500m. The cluster has free capacity. What happens?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod with no resource requests is scheduled. Then memory pressure builds on the node and the kubelet must evict Pods. Which Pod is evicted FIRST under standard QoS rules?$k8s$, $k8s$[{"id":"a","text":"Guaranteed Pods (requests == limits)"},{"id":"b","text":"Burstable Pods (requests < limits)"},{"id":"c","text":"BestEffort Pods (no requests or limits)"},{"id":"d","text":"Pods marked critical via priorityClass"}]$k8s$::jsonb, $k8s$["c"]$k8s$::jsonb, $k8s$Eviction order under node pressure is BestEffort → Burstable → Guaranteed. BestEffort Pods (no requests/limits) are sacrificed first.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod with no resource requests is scheduled. Then memory pressure builds on the node and the kubelet must evict Pods. Which Pod is evicted FIRST under standard QoS rules?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A PersistentVolumeClaim with `accessModes: [ReadWriteOnce]` can be:$k8s$, $k8s$[{"id":"a","text":"Mounted read-write by exactly one node at a time."},{"id":"b","text":"Mounted read-write by every Pod in the namespace concurrently."},{"id":"c","text":"Mounted read-only by many nodes but not read-write."},{"id":"d","text":"Mounted read-write only by Pods in the same Pod."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$RWO permits read-write by ONE node (not Pod). Multiple Pods on that same node can mount it. RWX permits multi-node read-write.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A PersistentVolumeClaim with `accessModes: [ReadWriteOnce]` can be:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Service `api` of type ClusterIP selects Pods with label `app=api`. You scale the Deployment up by 2 Pods. What must you do for the new Pods to receive traffic?$k8s$, $k8s$[{"id":"a","text":"Update the Service's `targetPort` to the new Pod count."},{"id":"b","text":"Nothing — the EndpointSlice controller updates endpoints automatically as Pods become Ready."},{"id":"c","text":"Delete and recreate the Service."},{"id":"d","text":"Restart kube-proxy on every node."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$The EndpointSlice / Endpoints controller continuously reconciles Service backends to match Ready Pods of the selector. No manual action is needed.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Service `api` of type ClusterIP selects Pods with label `app=api`. You scale the Deployment up by 2 Pods. What must you do for the new Pods to receive traffic?$k8s$);
