INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Job must abort if it runs longer than 5 minutes regardless of retries. Which field enforces this?$k8s$, $k8s$[{"id":"a","text":"spec.activeDeadlineSeconds: 300"},{"id":"b","text":"spec.backoffLimit: 300"},{"id":"c","text":"spec.ttlSecondsAfterFinished: 300"},{"id":"d","text":"spec.completions: 300"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`activeDeadlineSeconds` is a hard wall-clock cap on the Job; once exceeded the Job is terminated and marked failed, overriding remaining retries.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Job must abort if it runs longer than 5 minutes regardless of retries. Which field enforces this?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$In a Pod spec, which field sets the command run by the container, overriding the image's ENTRYPOINT?$k8s$, $k8s$[{"id":"a","text":"spec.containers[].command"},{"id":"b","text":"spec.containers[].entrypoint"},{"id":"c","text":"spec.command"},{"id":"d","text":"spec.containers[].run"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$In Kubernetes, `containers[].command` overrides the image ENTRYPOINT and `containers[].args` overrides CMD.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$In a Pod spec, which field sets the command run by the container, overriding the image's ENTRYPOINT?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$An indexed Job (`completionMode: Indexed`) with `completions: 3` gives each Pod:$k8s$, $k8s$[{"id":"a","text":"A unique completion index (0,1,2) via the JOB_COMPLETION_INDEX env var."},{"id":"b","text":"The same index 0."},{"id":"c","text":"A random UUID only."},{"id":"d","text":"No way to distinguish Pods."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Indexed Jobs assign each Pod a unique index 0..completions-1, exposed via `JOB_COMPLETION_INDEX`, enabling static work partitioning.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$An indexed Job (`completionMode: Indexed`) with `completions: 3` gives each Pod:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about init containers vs sidecars.$k8s$, $k8s$[{"id":"a","text":"A plain init container must finish before the next container starts."},{"id":"b","text":"A native sidecar starts before app containers but does not block them by needing to complete."},{"id":"c","text":"Init containers and app containers always start at the same time."},{"id":"d","text":"Init containers can use a different image than the app container."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$Plain init containers run to completion sequentially; native sidecars (restartPolicy Always) start early but stay running. App containers do NOT start simultaneously with init containers. Each container can use any image.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about init containers vs sidecars.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which Dockerfile instruction declares a default command that is easily overridden by `docker run <img> <args>`?$k8s$, $k8s$[{"id":"a","text":"CMD"},{"id":"b","text":"ENTRYPOINT (exec form)"},{"id":"c","text":"RUN"},{"id":"d","text":"LABEL"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`CMD` provides default arguments that are replaced entirely when the user passes a command to `docker run`. `ENTRYPOINT` is harder to override (requires `--entrypoint`).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which Dockerfile instruction declares a default command that is easily overridden by `docker run <img> <args>`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod's init container writes a config file to a shared emptyDir; the app container reads it. If the init container fails repeatedly, the app container:$k8s$, $k8s$[{"id":"a","text":"Starts anyway and reads a stale file."},{"id":"b","text":"Never starts — the Pod stays in Init:Error/CrashLoopBackOff until the init container succeeds."},{"id":"c","text":"Is scheduled to another node."},{"id":"d","text":"Is converted into a Job."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$App containers do not start until ALL init containers succeed. A persistently failing init container keeps the Pod in an Init phase and the app never runs.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod's init container writes a config file to a shared emptyDir; the app container reads it. If the init container fails repeatedly, the app container:$k8s$);
