INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment selector is `matchLabels: {app: web}` but the Pod template labels are `{app: api}`. What happens on apply?$k8s$, $k8s$[{"id":"a","text":"It works; labels are advisory."},{"id":"b","text":"The Deployment is rejected/invalid because the selector must match the template labels."},{"id":"c","text":"A Service is auto-created."},{"id":"d","text":"It silently scales to zero."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$A Deployment's `spec.selector` must match the Pod template labels; a mismatch is a validation error and the object is rejected.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment selector is `matchLabels: {app: web}` but the Pod template labels are `{app: api}`. What happens on apply?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You ran `kubectl rollout undo deployment/web` but need to go to revision 2 specifically. Which command?$k8s$, $k8s$[{"id":"a","text":"kubectl rollout undo deployment/web --to-revision=2"},{"id":"b","text":"kubectl rollout undo deployment/web -r 2"},{"id":"c","text":"kubectl rollback deployment/web 2"},{"id":"d","text":"kubectl set revision deployment/web 2"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl rollout undo deployment/<name> --to-revision=N` rolls back to a specific revision listed by `kubectl rollout history`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You ran `kubectl rollout undo deployment/web` but need to go to revision 2 specifically. Which command?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$Scaling a Deployment with `kubectl scale` creates a new ReplicaSet revision.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Scaling only changes the replica count on the existing ReplicaSet; it does NOT alter the Pod template, so no new revision is created. Only `spec.template` changes create revisions.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Scaling a Deployment with `kubectl scale` creates a new ReplicaSet revision.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment is stuck: new Pods are `Pending` due to insufficient memory and old Pods still serve traffic. With `maxUnavailable: 0`, the rollout:$k8s$, $k8s$[{"id":"a","text":"Forces old Pods down to make room."},{"id":"b","text":"Stalls — old Pods stay up (no downtime) until new Pods can be scheduled or the progress deadline triggers."},{"id":"c","text":"Deletes the Deployment."},{"id":"d","text":"Switches to Recreate automatically."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$With `maxUnavailable: 0`, the controller will not remove old Pods until replacements are Ready. If new Pods cannot schedule, the rollout stalls safely and may report ProgressDeadlineExceeded.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment is stuck: new Pods are `Pending` due to insufficient memory and old Pods still serve traffic. With `maxUnavailable: 0`, the rollout:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command edits a live Deployment in your default editor and applies on save?$k8s$, $k8s$[{"id":"a","text":"kubectl edit deployment/web"},{"id":"b","text":"kubectl modify deployment web"},{"id":"c","text":"kubectl patch deployment web --editor"},{"id":"d","text":"kubectl update deployment web"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl edit <resource>/<name>` opens the live object in `$EDITOR`; saving applies the change via a patch.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command edits a live Deployment in your default editor and applies on save?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment owns ReplicaSet `web-abc` (current) and `web-def` (old, 0 replicas). You delete ReplicaSet `web-abc` directly. What happens?$k8s$, $k8s$[{"id":"a","text":"The Deployment recreates a matching ReplicaSet and its Pods to reconcile desired state."},{"id":"b","text":"The Deployment is deleted too."},{"id":"c","text":"Nothing — the Pods keep running orphaned."},{"id":"d","text":"The old ReplicaSet web-def is promoted with the new image."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$The Deployment controller continuously reconciles; deleting its active ReplicaSet causes it to create a new ReplicaSet from the current template and restore the desired Pods.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment owns ReplicaSet `web-abc` (current) and `web-def` (old, 0 replicas). You delete ReplicaSet `web-abc` directly. What happens?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Helm: which command lists the currently installed releases in a namespace?$k8s$, $k8s$[{"id":"a","text":"helm list -n <namespace>"},{"id":"b","text":"helm get releases"},{"id":"c","text":"helm ps -n <namespace>"},{"id":"d","text":"helm show releases"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`helm list` (alias `helm ls`) shows installed releases; `-n` scopes to a namespace, `-A` lists across all namespaces.$k8s$, $k8s$[{"url":"https://helm.sh/docs/topics/charts/","label":"Helm Docs — Charts"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Helm: which command lists the currently installed releases in a namespace?$k8s$);
