INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A container restarts every ~40s. `kubectl describe pod` shows Last State Terminated, Reason Error, Exit Code 1, and a livenessProbe with periodSeconds 10 failureThreshold 3. The MOST likely root cause to investigate first is:$k8s$, $k8s$[{"id":"a","text":"The Service selector."},{"id":"b","text":"The application itself exiting/crashing (exit code 1) or failing its liveness endpoint — check kubectl logs --previous."},{"id":"c","text":"A NetworkPolicy."},{"id":"d","text":"The node's disk pressure."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Reason `Error` with exit code 1 plus a ~30s liveness window points to the app crashing or failing its health endpoint. `kubectl logs --previous` reveals the crash output.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A container restarts every ~40s. `kubectl describe pod` shows Last State Terminated, Reason Error, Exit Code 1, and a livenessProbe with periodSeconds 10 failureThreshold 3. The MOST likely root cause to investigate first is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 2, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A failing readiness probe causes the kubelet to restart the container.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Readiness only removes the Pod from Service endpoints; it never restarts the container. Liveness probe failures are what trigger restarts.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A failing readiness probe causes the kubelet to restart the container.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which command streams logs from the last 1 hour for a Pod and keeps following new lines?$k8s$, $k8s$[{"id":"a","text":"kubectl logs <pod> --since=1h -f"},{"id":"b","text":"kubectl logs <pod> --last=1h --stream"},{"id":"c","text":"kubectl logs <pod> -t 1h"},{"id":"d","text":"kubectl logs <pod> --range=1h --watch"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`--since=1h` limits to the last hour and `-f` follows. `--tail=N` instead limits to the last N lines.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command streams logs from the last 1 hour for a Pod and keeps following new lines?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod is stuck `Pending`. `kubectl describe pod` shows a FailedScheduling event "0/3 nodes available: insufficient cpu". The fix that does NOT require new nodes is:$k8s$, $k8s$[{"id":"a","text":"Lower the Pod's CPU request so it fits an existing node."},{"id":"b","text":"Add a livenessProbe."},{"id":"c","text":"Change the Service type."},{"id":"d","text":"Increase replicas."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Insufficient CPU at scheduling means the Pod's CPU REQUEST exceeds any node's allocatable. Reducing the request (or freeing capacity) lets the scheduler place it without adding nodes.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod is stuck `Pending`. `kubectl describe pod` shows a FailedScheduling event "0/3 nodes available: insufficient cpu". The fix that does NOT require new nodes is:$k8s$);
