INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod sets `runAsNonRoot: true` but the image's default user is root (UID 0) and no `runAsUser` is set. What happens at start?$k8s$, $k8s$[{"id":"a","text":"The container starts as root anyway."},{"id":"b","text":"The kubelet refuses to start the container (CreateContainerConfigError) because it would run as root."},{"id":"c","text":"Kubernetes auto-assigns UID 1000."},{"id":"d","text":"The Pod is OOMKilled."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`runAsNonRoot: true` makes the kubelet validate the effective user is non-root at start. If the image would run as UID 0, container creation fails rather than running privileged.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod sets `runAsNonRoot: true` but the image's default user is root (UID 0) and no `runAsUser` is set. What happens at start?$k8s$);
