INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about ConfigMaps and Secrets.$k8s$, $k8s$[{"id":"a","text":"Both can be mounted as volumes or injected as env vars."},{"id":"b","text":"A Secret's data values are base64-encoded in the manifest."},{"id":"c","text":"A ConfigMap can store binary data via the binaryData field."},{"id":"d","text":"Secrets are encrypted at rest by default without any extra configuration."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$ConfigMaps/Secrets both support volume and env consumption; Secret `data` is base64; ConfigMaps support `binaryData`. Encryption at rest requires explicit EncryptionConfiguration — it is NOT on by default.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"},{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about ConfigMaps and Secrets.$k8s$);
