INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A NetworkPolicy allows DNS egress. Which rule typically permits Pods to resolve names?$k8s$, $k8s$[{"id":"a","text":"egress to kube-system namespace / kube-dns Pods on UDP and TCP port 53"},{"id":"b","text":"egress to 0.0.0.0/0 port 443"},{"id":"c","text":"ingress from port 53"},{"id":"d","text":"egress to the API server on 6443"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$When a default-deny egress policy is in place, you must explicitly allow egress to the cluster DNS (CoreDNS/kube-dns) on port 53 (UDP and TCP) or name resolution breaks.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A NetworkPolicy allows DNS egress. Which rule typically permits Pods to resolve names?$k8s$);
