INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need pod-to-pod traffic blocked by default in namespace `secure`, allowing only explicitly permitted flows. The baseline policy is:$k8s$, $k8s$[{"id":"a","text":"A NetworkPolicy with podSelector: {} and policyTypes: [Ingress, Egress] with no rules (default-deny), then add allow policies."},{"id":"b","text":"A LoadBalancer Service."},{"id":"c","text":"Set hostNetwork: true on all Pods."},{"id":"d","text":"Delete CoreDNS."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A default-deny policy selecting all Pods with empty Ingress/Egress rule sets establishes a deny baseline; additive allow policies then open required paths (including DNS).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need pod-to-pod traffic blocked by default in namespace `secure`, allowing only explicitly permitted flows. The baseline policy is:$k8s$);
