INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Service `web` has endpoints but `curl web` from another Pod times out, while `curl <podIP>` works. The MOST likely cause is:$k8s$, $k8s$[{"id":"a","text":"A NetworkPolicy or DNS issue (the Service name/IP path is blocked or unresolved), not the Pods themselves."},{"id":"b","text":"The Pods are down."},{"id":"c","text":"The image is wrong."},{"id":"d","text":"The Deployment has zero replicas."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Direct Pod IP working but Service name failing isolates the problem to DNS resolution or a NetworkPolicy blocking the ClusterIP/DNS path — the Pods are healthy.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Service `web` has endpoints but `curl web` from another Pod times out, while `curl <podIP>` works. The MOST likely cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about Ingress.$k8s$, $k8s$[{"id":"a","text":"A single Ingress can fan out multiple hostnames to different Services."},{"id":"b","text":"TLS termination can be configured via spec.tls with a kubernetes.io/tls Secret."},{"id":"c","text":"Ingress natively load-balances raw TCP/UDP for arbitrary protocols."},{"id":"d","text":"pathType Prefix matches by path segments."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$Ingress is HTTP/HTTPS layer-7 routing — it does not natively handle arbitrary TCP/UDP (use a Service of type LoadBalancer/NodePort for that). It supports host fan-out, TLS termination, and prefix path matching.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P2$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about Ingress.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which Docker layer is rebuilt FIRST when only the application source code (added last in the Dockerfile) changes?$k8s$, $k8s$[{"id":"a","text":"The base image FROM layer."},{"id":"b","text":"The layer added immediately after the changed source line, and everything below."},{"id":"c","text":"The COPY/ADD layer containing the changed source and every layer AFTER it."},{"id":"d","text":"The entire image is rebuilt from scratch every time."}]$k8s$::jsonb, $k8s$["c"]$k8s$::jsonb, $k8s$Docker cache is invalidated at the first changed layer and every subsequent layer. Placing rarely-changing instructions early (e.g. dependency install) maximises cache reuse.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which Docker layer is rebuilt FIRST when only the application source code (added last in the Dockerfile) changes?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Two containers in one Pod need to share a directory. Which volume type is appropriate?$k8s$, $k8s$[{"id":"a","text":"emptyDir"},{"id":"b","text":"hostPath"},{"id":"c","text":"persistentVolumeClaim"},{"id":"d","text":"configMap"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`emptyDir` is created when the Pod is assigned to a node and shared among the Pod's containers. It is removed when the Pod terminates. hostPath ties to a specific node; PVC is typically for cross-Pod persistence.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Two containers in one Pod need to share a directory. Which volume type is appropriate?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about init containers.$k8s$, $k8s$[{"id":"a","text":"Init containers run to completion BEFORE app containers start."},{"id":"b","text":"Init containers can have their own resource requests/limits and securityContext."},{"id":"c","text":"Init containers run in parallel with app containers."},{"id":"d","text":"If an init container fails, the Pod is restarted (by default)."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$Init containers run sequentially before app containers — not in parallel. They have their own resources/securityContext. Default restartPolicy is Always, so an init failure triggers Pod restart.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/init-containers/","label":"Kubernetes Docs — Init Containers"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about init containers.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Job has `backoffLimit: 4`. What does this mean?$k8s$, $k8s$[{"id":"a","text":"The Job retries up to 4 times before being marked failed."},{"id":"b","text":"The Job runs at most 4 Pods in parallel."},{"id":"c","text":"The Job times out after 4 minutes."},{"id":"d","text":"The Job retains 4 completed Pods after success."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`backoffLimit` caps the number of retries on failure. After that many attempts, the Job reports Failed status.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Job has `backoffLimit: 4`. What does this mean?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which command pauses an in-progress rollout of Deployment `api`?$k8s$, $k8s$[{"id":"a","text":"kubectl rollout pause deployment/api"},{"id":"b","text":"kubectl rollout halt deployment/api"},{"id":"c","text":"kubectl scale deployment/api --pause"},{"id":"d","text":"kubectl deploy api --pause"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl rollout pause/resume deployment/<name>` pauses and resumes a rollout. Useful for canary-style staged updates.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command pauses an in-progress rollout of Deployment `api`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which kubectl subcommand creates resources from a manifest in a declarative, idempotent way?$k8s$, $k8s$[{"id":"a","text":"kubectl create -f manifest.yaml"},{"id":"b","text":"kubectl apply -f manifest.yaml"},{"id":"c","text":"kubectl run -f manifest.yaml"},{"id":"d","text":"kubectl replace -f manifest.yaml"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`kubectl apply` is the declarative command — it creates resources that do not exist and patches existing ones based on the manifest, tracking changes via the last-applied annotation.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which kubectl subcommand creates resources from a manifest in a declarative, idempotent way?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment's revisionHistoryLimit defaults to 10. What does it control?$k8s$, $k8s$[{"id":"a","text":"Maximum simultaneous rolling Pods."},{"id":"b","text":"Maximum number of OLD ReplicaSets retained for rollback."},{"id":"c","text":"Maximum age in days before a ReplicaSet is pruned."},{"id":"d","text":"Maximum number of replicas."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$`revisionHistoryLimit` keeps the last N old ReplicaSets so `kubectl rollout undo --to-revision=N` can target them. Older ones are garbage-collected.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment's revisionHistoryLimit defaults to 10. What does it control?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A blue/green deployment strategy on Kubernetes is typically implemented by:$k8s$, $k8s$[{"id":"a","text":"Running two Deployments (blue, green) behind one Service, switching the Service selector between them at cutover."},{"id":"b","text":"Using `strategy.type: Recreate` on a single Deployment."},{"id":"c","text":"Setting `maxUnavailable: 50%`."},{"id":"d","text":"Disabling the readiness probe during cutover."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Blue/green keeps two complete environments and flips the selector (or Ingress backend) atomically. Recreate is single-Deployment downtime updates, not blue/green.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A blue/green deployment strategy on Kubernetes is typically implemented by:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod has two containers `app` and `proxy`. How do you retrieve only the `app` container's logs?$k8s$, $k8s$[{"id":"a","text":"kubectl logs <pod> --container=app"},{"id":"b","text":"kubectl logs <pod>/app"},{"id":"c","text":"kubectl logs --filter=app <pod>"},{"id":"d","text":"kubectl exec <pod> -- logs app"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Use `-c`/`--container` to disambiguate containers when a Pod has more than one.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod has two containers `app` and `proxy`. How do you retrieve only the `app` container's logs?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$You add a readinessProbe to a fronting Pod. During slow startup the Pod reports Ready=False. What is the user-visible effect?$k8s$, $k8s$[{"id":"a","text":"The Pod is killed and restarted by the kubelet."},{"id":"b","text":"The Pod's IP is REMOVED from any backing Service's endpoints, so traffic is not routed to it."},{"id":"c","text":"The Pod is moved to another node."},{"id":"d","text":"The Deployment fails the rollout immediately."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Readiness gates Service endpoint membership but does NOT restart Pods. A rollout pauses if too few Pods become Ready (per maxUnavailable).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You add a readinessProbe to a fronting Pod. During slow startup the Pod reports Ready=False. What is the user-visible effect?$k8s$);
