INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A namespace has a `LimitRange` with default container CPU request 200m / limit 500m. You apply a Pod with NO resources specified. What happens?$k8s$, $k8s$[{"id":"a","text":"The Pod is rejected at admission."},{"id":"b","text":"The Pod is created with request 200m / limit 500m applied by the LimitRange admission controller."},{"id":"c","text":"The Pod runs with no requests/limits (LimitRange is advisory)."},{"id":"d","text":"The Pod runs but is marked Failed."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$LimitRange admission injects the namespace defaults into Pods that omit them. It can also enforce min/max bounds, rejecting Pods that violate them.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A namespace has a `LimitRange` with default container CPU request 200m / limit 500m. You apply a Pod with NO resources specified. What happens?$k8s$);
