INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about PersistentVolumes and PersistentVolumeClaims.$k8s$, $k8s$[{"id":"a","text":"A PVC binds to one PV at a time; the binding is exclusive."},{"id":"b","text":"StorageClasses enable dynamic provisioning — a matching PV is created on demand when the PVC is created."},{"id":"c","text":"A PVC can be expanded online if the StorageClass has `allowVolumeExpansion: true`."},{"id":"d","text":"Deleting a PVC always deletes the underlying PV regardless of reclaim policy."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$PV reclaim policy controls deletion: `Delete` removes the PV; `Retain` keeps it. So deletion of a PVC does NOT always delete the PV — depends on policy.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about PersistentVolumes and PersistentVolumeClaims.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Service `web` selects Pods with `app=web`. Two Pods have that label — one Ready, one NotReady. Endpoints for the Service contain:$k8s$, $k8s$[{"id":"a","text":"Both Pod IPs."},{"id":"b","text":"Only the Ready Pod's IP; the NotReady Pod is in `notReadyAddresses`."},{"id":"c","text":"Only the NotReady Pod's IP."},{"id":"d","text":"No endpoints until both are Ready."}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$EndpointSlices place Ready Pods in `addresses` and not-Ready Pods in `notReadyAddresses`. Only Ready endpoints receive traffic.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Service `web` selects Pods with `app=web`. Two Pods have that label — one Ready, one NotReady. Endpoints for the Service contain:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which Service field selects which Pods back the Service?$k8s$, $k8s$[{"id":"a","text":"spec.selector"},{"id":"b","text":"spec.podSelector"},{"id":"c","text":"spec.targetSelector"},{"id":"d","text":"metadata.labels"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`spec.selector` on a Service matches Pods by label and populates Endpoints. `podSelector` is a NetworkPolicy field; `metadata.labels` are the Service's own labels.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which Service field selects which Pods back the Service?$k8s$);
