INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A NetworkPolicy in namespace `prod` allows ingress from Pods labelled `role=frontend` in namespace `web`. Which selector pair is correct?$k8s$, $k8s$[{"id":"a","text":"ingress.from: [{ podSelector: { matchLabels: { role: frontend } } }]"},{"id":"b","text":"ingress.from: [{ namespaceSelector: { matchLabels: { kubernetes.io/metadata.name: web } }, podSelector: { matchLabels: { role: frontend } } }]"},{"id":"c","text":"ingress.from: [{ namespaceSelector: { matchLabels: { role: frontend } } }]"},{"id":"d","text":"ingress.from: [{ ipBlock: { cidr: 0.0.0.0/0 } }]"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$Cross-namespace selection requires BOTH a namespaceSelector (to match the source namespace) AND a podSelector (to match the source Pods). Option A would match only Pods in the same namespace.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A NetworkPolicy in namespace `prod` allows ingress from Pods labelled `role=frontend` in namespace `web`. Which selector pair is correct?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command adds a label `tier=backend` to an existing Pod `api`?$k8s$, $k8s$[{"id":"a","text":"kubectl label pod api tier=backend"},{"id":"b","text":"kubectl set label pod/api tier=backend"},{"id":"c","text":"kubectl annotate pod api tier=backend"},{"id":"d","text":"kubectl edit pod api --label tier=backend"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl label <resource> <name> key=value` adds/updates a label. Use `key-` to remove a label and `--overwrite` to change an existing one.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command adds a label `tier=backend` to an existing Pod `api`?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A workload needs exactly one Pod per node for a node-local agent. Which controller is designed for this?$k8s$, $k8s$[{"id":"a","text":"Deployment"},{"id":"b","text":"DaemonSet"},{"id":"c","text":"Job"},{"id":"d","text":"StatefulSet"}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$A DaemonSet ensures one Pod per (matching) node — used for log shippers, node exporters, and CNI agents. Deployments do not pin one Pod per node.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A workload needs exactly one Pod per node for a node-local agent. Which controller is designed for this?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$Containers in the same Pod can communicate over localhost because they share the Pod's network namespace.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$All containers in a Pod share one network namespace and IP, so they reach each other via `localhost`/127.0.0.1 and must not bind the same port.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Containers in the same Pod can communicate over localhost because they share the Pod's network namespace.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A CronJob keeps too many old Jobs around. Which fields cap retained finished Jobs?$k8s$, $k8s$[{"id":"a","text":"spec.successfulJobsHistoryLimit and spec.failedJobsHistoryLimit"},{"id":"b","text":"spec.backoffLimit and spec.completions"},{"id":"c","text":"spec.ttlSeconds and spec.maxJobs"},{"id":"d","text":"spec.concurrencyPolicy only"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$CronJob `successfulJobsHistoryLimit` (default 3) and `failedJobsHistoryLimit` (default 1) bound how many finished Jobs are retained for inspection.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/cron-jobs/","label":"Kubernetes Docs — CronJobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A CronJob keeps too many old Jobs around. Which fields cap retained finished Jobs?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which Pod spec field passes ARGS to the container, overriding the image CMD but not the ENTRYPOINT?$k8s$, $k8s$[{"id":"a","text":"spec.containers[].args"},{"id":"b","text":"spec.containers[].command"},{"id":"c","text":"spec.args"},{"id":"d","text":"spec.containers[].cmd"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`containers[].args` overrides the image CMD (the default arguments) while leaving the ENTRYPOINT intact. `containers[].command` overrides ENTRYPOINT.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which Pod spec field passes ARGS to the container, overriding the image CMD but not the ENTRYPOINT?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod has containers A and B sharing an emptyDir. A writes a ready file then exits 0; B waits for it. With `restartPolicy: Always`, what happens to A?$k8s$, $k8s$[{"id":"a","text":"A is restarted repeatedly even though it succeeded, because Always restarts on any exit."},{"id":"b","text":"A is never restarted."},{"id":"c","text":"The whole Pod is deleted."},{"id":"d","text":"A is converted to an init container."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$With `restartPolicy: Always`, the kubelet restarts a container that exits regardless of exit code. A short-lived setup step belongs in an init container, not a sidecar with Always.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod has containers A and B sharing an emptyDir. A writes a ready file then exits 0; B waits for it. With `restartPolicy: Always`, what happens to A?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about Jobs.$k8s$, $k8s$[{"id":"a","text":"parallelism controls how many Pods may run at once."},{"id":"b","text":"completions sets how many successful Pods are required."},{"id":"c","text":"A Job Pod template may use restartPolicy: Always."},{"id":"d","text":"backoffLimit caps failed retries before the Job is marked Failed."}]$k8s$::jsonb, $k8s$["a","b","d"]$k8s$::jsonb, $k8s$Job Pod templates must use `OnFailure` or `Never` (never `Always`). `parallelism`/`completions` shape concurrency and required successes; `backoffLimit` bounds retries.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/job/","label":"Kubernetes Docs — Jobs"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about Jobs.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which Dockerfile instruction is best for declaring a writable data location decoupled from the image layers?$k8s$, $k8s$[{"id":"a","text":"VOLUME /data"},{"id":"b","text":"MOUNT /data"},{"id":"c","text":"STORAGE /data"},{"id":"d","text":"PERSIST /data"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`VOLUME` declares a mount point whose contents live outside the image's union filesystem. In Kubernetes you typically supply that path via a Pod volume (emptyDir/PVC).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which Dockerfile instruction is best for declaring a writable data location decoupled from the image layers?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Design and Build$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod must be scheduled only onto nodes labelled `disktype=ssd`. The simplest mechanism is:$k8s$, $k8s$[{"id":"a","text":"spec.nodeSelector: { disktype: ssd }"},{"id":"b","text":"A NetworkPolicy"},{"id":"c","text":"A readinessProbe"},{"id":"d","text":"spec.serviceAccountName"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`nodeSelector` is the simplest node-constraint: the Pod schedules only on nodes carrying all the specified labels. Affinity offers richer expressions.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/pods/","label":"Kubernetes Docs — Pods"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod must be scheduled only onto nodes labelled `disktype=ssd`. The simplest mechanism is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command outputs a Deployment manifest without creating it, to save to a file?$k8s$, $k8s$[{"id":"a","text":"kubectl create deployment web --image=nginx --dry-run=client -o yaml"},{"id":"b","text":"kubectl create deployment web --image=nginx --no-create"},{"id":"c","text":"kubectl get deployment web -o yaml --template"},{"id":"d","text":"kubectl deploy web --image=nginx --export"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`--dry-run=client -o yaml` renders the manifest client-side without contacting the API server, the standard scaffold-then-edit workflow.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command outputs a Deployment manifest without creating it, to save to a file?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Deployment's old ReplicaSets are piling up consuming etcd. The field to reduce retention is:$k8s$, $k8s$[{"id":"a","text":"spec.revisionHistoryLimit"},{"id":"b","text":"spec.replicas"},{"id":"c","text":"spec.minReadySeconds"},{"id":"d","text":"spec.progressDeadlineSeconds"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Lowering `revisionHistoryLimit` reduces how many old ReplicaSets are kept (default 10). Fewer revisions means less clutter but fewer rollback targets.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Deployment's old ReplicaSets are piling up consuming etcd. The field to reduce retention is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$Which command annotates a Deployment with a change-cause so it appears in rollout history?$k8s$, $k8s$[{"id":"a","text":"kubectl annotate deployment/web kubernetes.io/change-cause=\"bump to 1.27\""},{"id":"b","text":"kubectl set cause deployment/web \"bump to 1.27\""},{"id":"c","text":"kubectl rollout cause deployment/web --msg=\"bump\""},{"id":"d","text":"kubectl label deployment/web change-cause=bump"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$The `kubernetes.io/change-cause` annotation populates the CHANGE-CAUSE column in `kubectl rollout history`, documenting why each revision was created.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command annotates a Deployment with a change-cause so it appears in rollout history?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 3, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$With RollingUpdate, `maxSurge` and `maxUnavailable` cannot both be 0.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$If both are 0 the rollout can neither create an extra Pod nor drop an existing one, so it could never make progress; Kubernetes rejects that combination.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$With RollingUpdate, `maxSurge` and `maxUnavailable` cannot both be 0.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$You set `kubectl rollout pause deployment/web`, then change the image twice, then `kubectl rollout resume`. How many new ReplicaSets/rollouts occur?$k8s$, $k8s$[{"id":"a","text":"One — the paused state batches the changes; resuming rolls out the final template once."},{"id":"b","text":"Two — one rollout per image change."},{"id":"c","text":"Zero — pause cancels changes."},{"id":"d","text":"Three."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$While paused, the Deployment accumulates spec changes without rolling out. Resuming performs a single rollout to the latest template, enabling staged multi-edit canaries.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You set `kubectl rollout pause deployment/web`, then change the image twice, then `kubectl rollout resume`. How many new ReplicaSets/rollouts occur?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Deployment$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command deletes all resources defined in a manifest file?$k8s$, $k8s$[{"id":"a","text":"kubectl delete -f app.yaml"},{"id":"b","text":"kubectl remove -f app.yaml"},{"id":"c","text":"kubectl destroy -f app.yaml"},{"id":"d","text":"kubectl apply -f app.yaml --delete"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl delete -f <file>` removes every object the manifest declares, useful for tearing down a declaratively created app.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/workloads/controllers/deployment/","label":"Kubernetes Docs — Deployments"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command deletes all resources defined in a manifest file?$k8s$);
