INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A liveness httpGet probe returns HTTP 500. The kubelet treats this as:$k8s$, $k8s$[{"id":"a","text":"A failure (only 2xx/3xx are success)."},{"id":"b","text":"A success (any response means alive)."},{"id":"c","text":"Unknown until timeout."},{"id":"d","text":"A readiness signal only."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$httpGet probes succeed only on status codes 200–399. A 4xx/5xx counts as a failure toward `failureThreshold`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A liveness httpGet probe returns HTTP 500. The kubelet treats this as:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You need to copy a log file out of a running Pod's container to your machine. Which command?$k8s$, $k8s$[{"id":"a","text":"kubectl cp <namespace>/<pod>:/var/log/app.log ./app.log"},{"id":"b","text":"kubectl scp <pod>:/var/log/app.log ."},{"id":"c","text":"kubectl logs <pod> > app.log only works for stdout"},{"id":"d","text":"kubectl get file <pod>:/var/log/app.log"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl cp` copies files between a container and the local filesystem (it requires `tar` in the container). It is the way to retrieve files not written to stdout.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You need to copy a log file out of a running Pod's container to your machine. Which command?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL correct probe-tuning statements for a slow-starting app.$k8s$, $k8s$[{"id":"a","text":"A startupProbe with a generous failureThreshold × periodSeconds protects boot from liveness kills."},{"id":"b","text":"Once the startupProbe succeeds, liveness and readiness probes begin."},{"id":"c","text":"initialDelaySeconds on liveness can also mitigate slow starts but is less precise than a startupProbe."},{"id":"d","text":"A startupProbe runs for the entire Pod lifetime."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$startupProbe runs only until it first succeeds, then hands off to liveness/readiness. A long startup budget is its purpose; `initialDelaySeconds` is a coarser alternative.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-liveness-readiness-startup-probes/","label":"Kubernetes Docs — Liveness/Readiness/Startup Probes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL correct probe-tuning statements for a slow-starting app.$k8s$);
