INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod shows STATUS `ImagePullBackOff`. The first command to confirm the cause is:$k8s$, $k8s$[{"id":"a","text":"kubectl describe pod <pod> (read the Events for the pull error/auth failure)"},{"id":"b","text":"kubectl logs <pod>"},{"id":"c","text":"kubectl top pod <pod>"},{"id":"d","text":"kubectl exec <pod> -- sh"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$There are no logs for a container that never started. `kubectl describe pod` Events show the exact pull error: wrong tag, missing image, or registry auth failure.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/cluster-administration/logging/","label":"Kubernetes Docs — Logging Architecture"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod shows STATUS `ImagePullBackOff`. The first command to confirm the cause is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Observability and Maintenance$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod terminated with exit code 137. This typically indicates:$k8s$, $k8s$[{"id":"a","text":"The process was killed by SIGKILL (often the OOM killer or a failed graceful shutdown)."},{"id":"b","text":"A successful completion."},{"id":"c","text":"A configuration parse error."},{"id":"d","text":"A DNS failure."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Exit code 137 = 128 + 9 (SIGKILL). Common causes are an OOMKill (memory limit exceeded) or termination after the grace period elapsed.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod terminated with exit code 137. This typically indicates:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A specific Secret key `tls.key` should be projected to file path `keys/server.key` with mode 0400. Which volume config?$k8s$, $k8s$[{"id":"a","text":"secret: { secretName: s, items: [{ key: tls.key, path: keys/server.key, mode: 0400 }] }"},{"id":"b","text":"secret: { secretName: s, file: keys/server.key }"},{"id":"c","text":"configMap: { name: s, key: tls.key }"},{"id":"d","text":"secret: { secretName: s, env: tls.key }"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A secret volume's `items` lets you select specific keys, set the in-Pod relative `path`, and per-file `mode` permissions.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/secret/","label":"Kubernetes Docs — Secrets"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A specific Secret key `tls.key` should be projected to file path `keys/server.key` with mode 0400. Which volume config?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod must run with seccomp profile RuntimeDefault. Which field sets this?$k8s$, $k8s$[{"id":"a","text":"spec.securityContext.seccompProfile.type: RuntimeDefault"},{"id":"b","text":"spec.containers[].seccomp: default"},{"id":"c","text":"metadata.annotations.seccomp: runtime/default"},{"id":"d","text":"spec.runtimeClassName: seccomp"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$The modern field is `securityContext.seccompProfile.type` (RuntimeDefault or Localhost). The old annotation form is deprecated/removed.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod must run with seccomp profile RuntimeDefault. Which field sets this?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command updates an existing ConfigMap key idempotently from a manifest?$k8s$, $k8s$[{"id":"a","text":"kubectl apply -f configmap.yaml"},{"id":"b","text":"kubectl create configmap --update"},{"id":"c","text":"kubectl set configmap -f configmap.yaml"},{"id":"d","text":"kubectl patch configmap --from-file"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl apply -f` is the declarative, idempotent path: it creates the ConfigMap if absent and patches changed keys if present.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command updates an existing ConfigMap key idempotently from a manifest?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$SINGLE$k8s$::"QType", $k8s$A container needs the NET_ADMIN capability but the cluster enforces the Baseline Pod Security Standard. The likely outcome is:$k8s$, $k8s$[{"id":"a","text":"The Pod is rejected/denied by the namespace's Pod Security admission because NET_ADMIN is disallowed under Baseline/Restricted."},{"id":"b","text":"It works with no restriction."},{"id":"c","text":"Kubernetes silently drops only that capability and continues."},{"id":"d","text":"It forces privileged mode automatically."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Pod Security admission Baseline/Restricted profiles forbid adding most capabilities (only a small set is allowed). A Pod requesting NET_ADMIN is rejected in an enforcing namespace.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A container needs the NET_ADMIN capability but the cluster enforces the Baseline Pod Security Standard. The likely outcome is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod should disable mounting the default ServiceAccount token. Which Pod field?$k8s$, $k8s$[{"id":"a","text":"spec.automountServiceAccountToken: false"},{"id":"b","text":"spec.serviceAccountName: none"},{"id":"c","text":"spec.containers[].mountToken: false"},{"id":"d","text":"metadata.annotations.token: disabled"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Setting `automountServiceAccountToken: false` at the Pod (or ServiceAccount) level stops projecting the API token, reducing exposure for Pods that never call the API.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/configure-service-account/","label":"Kubernetes Docs — ServiceAccounts"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod should disable mounting the default ServiceAccount token. Which Pod field?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod requests `memory: 256Mi` and limits `memory: 256Mi`, and CPU request==limit. Its QoS class is:$k8s$, $k8s$[{"id":"a","text":"Guaranteed"},{"id":"b","text":"Burstable"},{"id":"c","text":"BestEffort"},{"id":"d","text":"Critical"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$When every container has requests equal to limits for both CPU and memory, the Pod is `Guaranteed` — the last to be evicted under node pressure.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/manage-resources-containers/","label":"Kubernetes Docs — Resource Management"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod requests `memory: 256Mi` and limits `memory: 256Mi`, and CPU request==limit. Its QoS class is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A ConfigMap mounted as a volume reflects updates in the container's filesystem after the kubelet sync, but subPath mounts do NOT receive updates.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Whole-volume ConfigMap mounts update on sync, but a `subPath` mount is resolved once at start and is NOT updated when the ConfigMap changes.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A ConfigMap mounted as a volume reflects updates in the container's filesystem after the kubelet sync, but subPath mounts do NOT receive updates.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$An app reads its config from `/config/app.yaml`. You want this sourced from ConfigMap key `app.yaml`. Which mount is correct?$k8s$, $k8s$[{"id":"a","text":"A configMap volume with items mapping key app.yaml → path app.yaml, mounted at /config"},{"id":"b","text":"envFrom configMapRef"},{"id":"c","text":"A secret volume"},{"id":"d","text":"hostPath /config"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Mounting the ConfigMap as a volume (optionally using `items` to control filenames) places `app.yaml` at `/config/app.yaml` for file-based config consumption.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/configuration/configmap/","label":"Kubernetes Docs — ConfigMaps"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$An app reads its config from `/config/app.yaml`. You want this sourced from ConfigMap key `app.yaml`. Which mount is correct?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about SecurityContext.$k8s$, $k8s$[{"id":"a","text":"runAsUser can be set at Pod or container level; the container value wins for that container."},{"id":"b","text":"allowPrivilegeEscalation is a container-level field."},{"id":"c","text":"fsGroup is a Pod-level field affecting volume ownership."},{"id":"d","text":"privileged: true is required to run as a non-root user."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$Running as non-root needs `runAsNonRoot`/`runAsUser`, NOT privileged (privileged grants near-host access). Pod vs container precedence, container-only `allowPrivilegeEscalation`, and Pod-level `fsGroup` are all correct.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about SecurityContext.$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A PVC with StorageClass `standard` and `allowVolumeExpansion: true` needs more space. The supported way to grow it is:$k8s$, $k8s$[{"id":"a","text":"Edit the PVC's spec.resources.requests.storage to a larger value and apply."},{"id":"b","text":"Delete and recreate the PVC (data loss)."},{"id":"c","text":"Edit the PV capacity directly only."},{"id":"d","text":"Scale the Deployment."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$When the StorageClass allows expansion, increasing the PVC's requested storage triggers an online (or after-restart) volume resize without recreating the claim.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/storage/persistent-volumes/","label":"Kubernetes Docs — Persistent Volumes"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A PVC with StorageClass `standard` and `allowVolumeExpansion: true` needs more space. The supported way to grow it is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Application Environment, Configuration and Security$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod must NOT share the host's PID namespace. Which is the safe default to keep?$k8s$, $k8s$[{"id":"a","text":"spec.hostPID: false (the default)"},{"id":"b","text":"spec.hostPID: true"},{"id":"c","text":"spec.shareProcessNamespace: true with hostPID"},{"id":"d","text":"spec.hostNetwork: true"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Leaving `hostPID` false (default) isolates the Pod from host processes. Setting it true exposes/inspects host PIDs and is a security concern best avoided.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/tasks/configure-pod-container/security-context/","label":"Kubernetes Docs — SecurityContext"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod must NOT share the host's PID namespace. Which is the safe default to keep?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 2, $k8s$SINGLE$k8s$::"QType", $k8s$Which command creates a ClusterIP Service for an existing Pod labelled `app=cache` on port 6379?$k8s$, $k8s$[{"id":"a","text":"kubectl expose pod <pod> --port=6379 --name=cache"},{"id":"b","text":"kubectl create svc <pod> --port=6379"},{"id":"c","text":"kubectl service expose pod <pod> 6379"},{"id":"d","text":"kubectl run cache --expose --port=6379"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl expose pod <pod> --port=` creates a Service selecting that Pod's labels (ClusterIP by default). For Deployments use `kubectl expose deployment`.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Which command creates a ClusterIP Service for an existing Pod labelled `app=cache` on port 6379?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A NetworkPolicy `ingress.from` uses only `ipBlock: { cidr: 10.0.0.0/24 }`. This allows ingress from:$k8s$, $k8s$[{"id":"a","text":"Any source whose IP falls in 10.0.0.0/24 (subject to CNI handling of pod source IPs)."},{"id":"b","text":"Only Pods with a specific label."},{"id":"c","text":"All namespaces."},{"id":"d","text":"Nothing — ipBlock is invalid for ingress."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`ipBlock` matches by CIDR. It is typically used for off-cluster sources; pod-to-pod source IPs may be obscured by SNAT depending on the CNI.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A NetworkPolicy `ingress.from` uses only `ipBlock: { cidr: 10.0.0.0/24 }`. This allows ingress from:$k8s$);
