INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$TRUE_FALSE$k8s$::"QType", $k8s$A ClusterIP Service is reachable from outside the cluster by default.$k8s$, $k8s$[{"id":"a","text":"True"},{"id":"b","text":"False"},{"id":"c","text":""},{"id":"d","text":""}]$k8s$::jsonb, $k8s$["b"]$k8s$::jsonb, $k8s$ClusterIP is internal-only. External exposure needs NodePort, LoadBalancer, an Ingress, or port-forwarding.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A ClusterIP Service is reachable from outside the cluster by default.$k8s$);
