INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$You want to test a Service from your laptop without exposing it externally. Which command?$k8s$, $k8s$[{"id":"a","text":"kubectl port-forward service/web 8080:80"},{"id":"b","text":"kubectl expose service/web --external"},{"id":"c","text":"kubectl proxy service/web"},{"id":"d","text":"kubectl tunnel web 8080:80"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$`kubectl port-forward service/<svc> <local>:<svcPort>` tunnels a local port to the Service through the API server — handy for ad-hoc testing without changing Service type.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$You want to test a Service from your laptop without exposing it externally. Which command?$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$An Ingress with no `host` field on a rule matches:$k8s$, $k8s$[{"id":"a","text":"All inbound HTTP hosts (the rule is a default/catch-all for its paths)."},{"id":"b","text":"No traffic."},{"id":"c","text":"Only localhost."},{"id":"d","text":"Only HTTPS traffic."}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$A rule without `host` applies to requests for any hostname, acting as a default backend rule for the listed paths.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/ingress/","label":"Kubernetes Docs — Ingress"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$An Ingress with no `host` field on a rule matches:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 3, $k8s$SINGLE$k8s$::"QType", $k8s$A Pod needs to reach a Service in another namespace `data`. From namespace `app`, the correct DNS name for Service `pg` is:$k8s$, $k8s$[{"id":"a","text":"pg.data.svc.cluster.local (or short form pg.data)"},{"id":"b","text":"pg (resolves only same-namespace)"},{"id":"c","text":"data.pg.cluster.local"},{"id":"d","text":"pg.app.svc.cluster.local"}]$k8s$::jsonb, $k8s$["a"]$k8s$::jsonb, $k8s$Cross-namespace access uses `<svc>.<ns>` or the FQDN `<svc>.<ns>.svc.cluster.local`. The bare name only resolves within the caller's own namespace.$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/service/","label":"Kubernetes Docs — Services"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, true, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$A Pod needs to reach a Service in another namespace `data`. From namespace `app`, the correct DNS name for Service `pg` is:$k8s$);
INSERT INTO "Question" (id, "examId", domain, difficulty, type, stem, options, correct, explanation, "references", status, "generatedBy", "isTeaser", version, "createdAt", "updatedAt") SELECT gen_random_uuid()::text, e.id, $k8s$Services and Networking$k8s$, 4, $k8s$MULTI$k8s$::"QType", $k8s$Select ALL true statements about NetworkPolicies.$k8s$, $k8s$[{"id":"a","text":"They are namespaced resources."},{"id":"b","text":"Without a policy selecting a Pod, the Pod allows all traffic by default."},{"id":"c","text":"Selecting a Pod with policyTypes Ingress and no ingress rules denies all ingress to it."},{"id":"d","text":"NetworkPolicies are enforced even when the CNI plugin does not support them."}]$k8s$::jsonb, $k8s$["a","b","c"]$k8s$::jsonb, $k8s$NetworkPolicies are namespaced and additive; an unselected Pod defaults to allow-all; a selected Pod with empty ingress rules is default-deny ingress. Enforcement REQUIRES a policy-capable CNI (Calico, Cilium, etc.).$k8s$, $k8s$[{"url":"https://kubernetes.io/docs/concepts/services-networking/network-policies/","label":"Kubernetes Docs — Network Policies"}]$k8s$::jsonb, $k8s$PUBLISHED$k8s$::"QStatus", $k8s$manual:ckad-seed$k8s$, false, 1, NOW(), NOW() FROM "Exam" e WHERE e.code = $k8s$CKAD-P3$k8s$ AND NOT EXISTS (SELECT 1 FROM "Question" q2 WHERE q2."examId" = e.id AND q2.stem = $k8s$Select ALL true statements about NetworkPolicies.$k8s$);
